#include "biblia.h"

void Biblia::CarregarJoao(Biblia* b) {
    b->dados[JOAO].nome = wxT("João");

    b->dados[JOAO].capitulos[1].versos[1] = wxT("No princípio era o Verbo, e o Verbo estava com Deus, e o Verbo era Deus.");
    b->dados[JOAO].capitulos[1].versos[2] = wxT("Ele estava no princípio com Deus.");
    b->dados[JOAO].capitulos[1].versos[3] = wxT("Todas as coisas foram feitas por intermédio dele, e sem ele nada do que foi feito se fez.");
    b->dados[JOAO].capitulos[1].versos[4] = wxT("Nele estava a vida, e a vida era a luz dos homens;");
    b->dados[JOAO].capitulos[1].versos[5] = wxT("a luz resplandece nas trevas, e as trevas não prevaleceram contra ela.");
    b->dados[JOAO].capitulos[1].versos[6] = wxT("Houve um homem enviado de Deus, cujo nome era João.");
    b->dados[JOAO].capitulos[1].versos[7] = wxT("Este veio como testemunha, a fim de dar testemunho da luz, para que todos cressem por meio dele.");
    b->dados[JOAO].capitulos[1].versos[8] = wxT("Ele não era a luz, mas veio para dar testemunho da luz.");
    b->dados[JOAO].capitulos[1].versos[9] = wxT("Pois a verdadeira luz, que alumia a todo homem, estava chegando ao mundo.");
    b->dados[JOAO].capitulos[1].versos[10] = wxT("Estava ele no mundo, e o mundo foi feito por intermédio dele, e o mundo não o conheceu.");
    b->dados[JOAO].capitulos[1].versos[11] = wxT("Veio para o que era seu, e os seus não o receberam.");
    b->dados[JOAO].capitulos[1].versos[12] = wxT("Mas, a todos quantos o receberam, aos que crêem no seu nome, deu-lhes o poder de se tornarem filhos de Deus;");
    b->dados[JOAO].capitulos[1].versos[13] = wxT("os quais não nasceram do sangue, nem da vontade da carne, nem da vontade do varão, mas de Deus.");
    b->dados[JOAO].capitulos[1].versos[14] = wxT("E o Verbo se fez carne, e habitou entre nós, cheio de graça e de verdade; e vimos a sua glória, como a glória do unigênito do Pai.");
    b->dados[JOAO].capitulos[1].versos[15] = wxT("João deu testemunho dele, e clamou, dizendo: Este é aquele de quem eu disse: O que vem depois de mim, passou adiante de mim; porque antes de mim ele já existia.");
    b->dados[JOAO].capitulos[1].versos[16] = wxT("Pois todos nós recebemos da sua plenitude, e graça sobre graça.");
    b->dados[JOAO].capitulos[1].versos[17] = wxT("Porque a lei foi dada por meio de Moisés; a graça e a verdade vieram por Jesus Cristo.");
    b->dados[JOAO].capitulos[1].versos[18] = wxT("Ninguém jamais viu a Deus. O Deus unigênito, que está no seio do Pai, esse o deu a conhecer.");
    b->dados[JOAO].capitulos[1].versos[19] = wxT("E este foi o testemunho de João, quando os judeus lhe enviaram de Jerusalém sacerdotes e levitas para que lhe perguntassem: Quem és tu?");
    b->dados[JOAO].capitulos[1].versos[20] = wxT("Ele, pois, confessou e não negou; sim, confessou: Eu não sou o Cristo.");
    b->dados[JOAO].capitulos[1].versos[21] = wxT("Ao que lhe perguntaram: Pois que? És tu Elias? Respondeu ele: Não sou. És tu o profeta? E respondeu: Não.");
    b->dados[JOAO].capitulos[1].versos[22] = wxT("Disseram-lhe, pois: Quem és? para podermos dar resposta aos que nos enviaram; que dizes de ti mesmo?");
    b->dados[JOAO].capitulos[1].versos[23] = wxT("Respondeu ele: Eu sou a voz do que clama no deserto: Endireitai o caminho do Senhor, como disse o profeta Isaías.");
    b->dados[JOAO].capitulos[1].versos[24] = wxT("E os que tinham sido enviados eram dos fariseus.");
    b->dados[JOAO].capitulos[1].versos[25] = wxT("Então lhe perguntaram: Por que batizas, pois, se tu não és o Cristo, nem Elias, nem o profeta?");
    b->dados[JOAO].capitulos[1].versos[26] = wxT("Respondeu-lhes João: Eu batizo em água; no meio de vós está um a quem vós não conheceis.");
    b->dados[JOAO].capitulos[1].versos[27] = wxT("aquele que vem depois de mim, de quem eu não sou digno de desatar a correia da alparca.");
    b->dados[JOAO].capitulos[1].versos[28] = wxT("Estas coisas aconteceram em Betânia, além do Jordão, onde João estava batizando.");
    b->dados[JOAO].capitulos[1].versos[29] = wxT("No dia seguinte João viu a Jesus, que vinha para ele, e disse: Eis o Cordeiro de Deus, que tira o pecado do mundo.");
    b->dados[JOAO].capitulos[1].versos[30] = wxT("este é aquele de quem eu disse: Depois de mim vem um varão que passou adiante de mim, porque antes de mim ele já existia.");
    b->dados[JOAO].capitulos[1].versos[31] = wxT("Eu não o conhecia; mas, para que ele fosse manifestado a Israel, é que vim batizando em água.");
    b->dados[JOAO].capitulos[1].versos[32] = wxT("E João deu testemunho, dizendo: Vi o Espírito descer do céu como pomba, e repousar sobre ele.");
    b->dados[JOAO].capitulos[1].versos[33] = wxT("Eu não o conhecia; mas o que me enviou a batizar em água, esse me disse: Aquele sobre quem vires descer o Espírito, e sobre ele permanecer, esse é o que batiza no Espírito Santo.");
    b->dados[JOAO].capitulos[1].versos[34] = wxT("Eu mesmo vi e já vos dei testemunho de que este é o Filho de Deus.");
    b->dados[JOAO].capitulos[1].versos[35] = wxT("No dia seguinte João estava outra vez ali, com dois dos seus discípulos");
    b->dados[JOAO].capitulos[1].versos[36] = wxT("e, olhando para Jesus, que passava, disse: Eis o Cordeiro de Deus!");
    b->dados[JOAO].capitulos[1].versos[37] = wxT("Aqueles dois discípulos ouviram-no dizer isto, e seguiram a Jesus.");
    b->dados[JOAO].capitulos[1].versos[38] = wxT("Voltando-se Jesus e vendo que o seguiam, perguntou-lhes: Que buscais? Disseram-lhe eles: rabi {que, traduzido, quer dizer Mestre}, onde pousas?");
    b->dados[JOAO].capitulos[1].versos[39] = wxT("Respondeu-lhes: Vinde, e vereis. Foram, pois, e viram onde pousava; e passaram o dia com ele; era cerca da hora décima.");
    b->dados[JOAO].capitulos[1].versos[40] = wxT("André, irmão de Simão Pedro, era um dos dois que ouviram João falar, e que seguiram a Jesus.");
    b->dados[JOAO].capitulos[1].versos[41] = wxT("Ele achou primeiro a seu irmão Simão, e disse-lhe: Havemos achado o Messias {que, traduzido, quer dizer Cristo}.");
    b->dados[JOAO].capitulos[1].versos[42] = wxT("E o levou a Jesus. Jesus, fixando nele o olhar, disse: Tu és Simão, filho de João, tu serás chamado Cefas {que quer dizer Pedro}.");
    b->dados[JOAO].capitulos[1].versos[43] = wxT("No dia seguinte Jesus resolveu partir para a Galiléia, e achando a Felipe disse-lhe: Segue-me.");
    b->dados[JOAO].capitulos[1].versos[44] = wxT("Ora, Felipe era de Betsaida, cidade de André e de Pedro.");
    b->dados[JOAO].capitulos[1].versos[45] = wxT("Felipe achou a Natanael, e disse-lhe: Acabamos de achar aquele de quem escreveram Moisés na lei, e os profetas: Jesus de Nazaré, filho de José.");
    b->dados[JOAO].capitulos[1].versos[46] = wxT("Perguntou-lhe Natanael: Pode haver coisa bem vinda de Nazaré? Disse-lhe Felipe: Vem e vê.");
    b->dados[JOAO].capitulos[1].versos[47] = wxT("Jesus, vendo Natanael aproximar-se dele, disse a seu respeito: Eis um verdadeiro israelita, em quem não há dolo!");
    b->dados[JOAO].capitulos[1].versos[48] = wxT("Perguntou-lhe Natanael: Donde me conheces? Respondeu-lhe Jesus: Antes que Felipe te chamasse, eu te vi, quando estavas debaixo da figueira.");
    b->dados[JOAO].capitulos[1].versos[49] = wxT("Respondeu-lhe Natanael: Rabi, tu és o Filho de Deus, tu és rei de Israel.");
    b->dados[JOAO].capitulos[1].versos[50] = wxT("Ao que lhe disse Jesus: Porque te disse: Vi-te debaixo da figueira, crês? coisas maiores do que estas verás.");
    b->dados[JOAO].capitulos[1].versos[51] = wxT("E acrescentou: Em verdade, em verdade vos digo que vereis o céu aberto, e os anjos de Deus subindo e descendo sobre o Filho do homem.");

    b->dados[JOAO].capitulos[2].versos[1] = wxT("Três dias depois, houve um casamento em Caná da Galiléia, e estava ali a mãe de Jesus;");
    b->dados[JOAO].capitulos[2].versos[2] = wxT("e foi também convidado Jesus com seus discípulos para o casamento.");
    b->dados[JOAO].capitulos[2].versos[3] = wxT("E, tendo acabado o vinho, a mãe de Jesus lhe disse: Eles não têm vinho.");
    b->dados[JOAO].capitulos[2].versos[4] = wxT("Respondeu-lhes Jesus: Mulher, que tenho eu contigo? Ainda não é chegada a minha hora.");
    b->dados[JOAO].capitulos[2].versos[5] = wxT("Disse então sua mãe aos serventes: Fazei tudo quanto ele vos disser.");
    b->dados[JOAO].capitulos[2].versos[6] = wxT("Ora, estavam ali postas seis talhas de pedra, para as purificações dos judeus, e em cada uma cabiam duas ou três metretas.");
    b->dados[JOAO].capitulos[2].versos[7] = wxT("Ordenou-lhe Jesus: Enchei de água essas talhas. E encheram-nas até em cima.");
    b->dados[JOAO].capitulos[2].versos[8] = wxT("Então lhes disse: Tirai agora, e levai ao mestre-sala. E eles o fizeram.");
    b->dados[JOAO].capitulos[2].versos[9] = wxT("Quando o mestre-sala provou a água tornada em vinho, não sabendo donde era, se bem que o sabiam os serventes que tinham tirado a água, chamou o mestre-sala ao noivo");
    b->dados[JOAO].capitulos[2].versos[10] = wxT("e lhe disse: Todo homem põe primeiro o vinho bom e, quando já têm bebido bem, então o inferior; mas tu guardaste até agora o bom vinho.");
    b->dados[JOAO].capitulos[2].versos[11] = wxT("Assim deu Jesus início aos seus sinais em Caná da Galiléia, e manifestou a sua glória; e os seus discípulos creram nele.");
    b->dados[JOAO].capitulos[2].versos[12] = wxT("Depois disso desceu a Cafarnaum, ele, sua mãe, seus irmãos, e seus discípulos; e ficaram ali não muitos dias.");
    b->dados[JOAO].capitulos[2].versos[13] = wxT("Estando próxima a páscoa dos judeus, Jesus subiu a Jerusalém.");
    b->dados[JOAO].capitulos[2].versos[14] = wxT("E achou no templo os que vendiam bois, ovelhas e pombas, e também os cambistas ali sentados;");
    b->dados[JOAO].capitulos[2].versos[15] = wxT("e tendo feito um azorrague de cordas, lançou todos fora do templo, bem como as ovelhas e os bois; e espalhou o dinheiro dos cambistas, e virou-lhes as mesas;");
    b->dados[JOAO].capitulos[2].versos[16] = wxT("e disse aos que vendiam as pombas: Tirai daqui estas coisas; não façais da casa de meu Pai casa de negócio.");
    b->dados[JOAO].capitulos[2].versos[17] = wxT("Lembraram-se então os seus discípulos de que está escrito: O zelo da tua casa me devorará.");
    b->dados[JOAO].capitulos[2].versos[18] = wxT("Protestaram, pois, os judeus, perguntando-lhe: Que sinal de autoridade nos mostras, uma vez que fazes isto?");
    b->dados[JOAO].capitulos[2].versos[19] = wxT("Respondeu-lhes Jesus: Derribai este santuário, e em três dias o levantarei.");
    b->dados[JOAO].capitulos[2].versos[20] = wxT("Disseram, pois, os judeus: Em quarenta e seis anos foi edificado este santuário, e tu o levantarás em três dias?");
    b->dados[JOAO].capitulos[2].versos[21] = wxT("Mas ele falava do santuário do seu corpo.");
    b->dados[JOAO].capitulos[2].versos[22] = wxT("Quando, pois ressurgiu dentre os mortos, seus discípulos se lembraram de que dissera isto, e creram na Escritura, e na palavra que Jesus havia dito.");
    b->dados[JOAO].capitulos[2].versos[23] = wxT("Ora, estando ele em Jerusalém pela festa da páscoa, muitos, vendo os sinais que fazia, creram no seu nome.");
    b->dados[JOAO].capitulos[2].versos[24] = wxT("Mas o próprio Jesus não confiava a eles, porque os conhecia a todos,");
    b->dados[JOAO].capitulos[2].versos[25] = wxT("e não necessitava de que alguém lhe desse testemunho do homem, pois bem sabia o que havia no homem.");

    b->dados[JOAO].capitulos[3].versos[1] = wxT("Ora, havia entre os fariseus um homem chamado Nicodemos, um dos principais dos judeus.");
    b->dados[JOAO].capitulos[3].versos[2] = wxT("Este foi ter com Jesus, de noite, e disse-lhe: Rabi, sabemos que és Mestre, vindo de Deus; pois ninguém pode fazer estes sinais que tu fazes, se Deus não estiver com ele.");
    b->dados[JOAO].capitulos[3].versos[3] = wxT("Respondeu-lhe Jesus: Em verdade, em verdade te digo que se alguém não nascer de novo, não pode ver o reino de Deus.");
    b->dados[JOAO].capitulos[3].versos[4] = wxT("Perguntou-lhe Nicodemos: Como pode um homem nascer, sendo velho? porventura pode tornar a entrar no ventre de sua mãe, e nascer?");
    b->dados[JOAO].capitulos[3].versos[5] = wxT("Jesus respondeu: Em verdade, em verdade te digo que se alguém não nascer da água e do Espírito, não pode entrar no reino de Deus.");
    b->dados[JOAO].capitulos[3].versos[6] = wxT("O que é nascido da carne é carne, e o que é nascido do Espírito é espírito.");
    b->dados[JOAO].capitulos[3].versos[7] = wxT("Não te admires de eu te haver dito: Necessário vos é nascer de novo.");
    b->dados[JOAO].capitulos[3].versos[8] = wxT("O vento sopra onde quer, e ouves a sua voz; mas não sabes donde vem, nem para onde vai; assim é todo aquele que é nascido do Espírito.");
    b->dados[JOAO].capitulos[3].versos[9] = wxT("Perguntou-lhe Nicodemos: Como pode ser isto?");
    b->dados[JOAO].capitulos[3].versos[10] = wxT("Respondeu-lhe Jesus: Tu és mestre em Israel, e não entendes estas coisas?");
    b->dados[JOAO].capitulos[3].versos[11] = wxT("Em verdade, em verdade te digo que nós dizemos o que sabemos e testemunhamos o que temos visto; e não aceitais o nosso testemunho!");
    b->dados[JOAO].capitulos[3].versos[12] = wxT("Se vos falei de coisas terrestres, e não credes, como crereis, se vos falar das celestiais?");
    b->dados[JOAO].capitulos[3].versos[13] = wxT("Ora, ninguém subiu ao céu, senão o que desceu do céu, o Filho do homem.");
    b->dados[JOAO].capitulos[3].versos[14] = wxT("E como Moisés levantou a serpente no deserto, assim importa que o Filho do homem seja levantado;");
    b->dados[JOAO].capitulos[3].versos[15] = wxT("para que todo aquele que nele crê tenha a vida eterna.");
    b->dados[JOAO].capitulos[3].versos[16] = wxT("Porque Deus amou o mundo de tal maneira que deu o seu Filho unigênito, para que todo aquele que nele crê não pereça, mas tenha a vida eterna.");
    b->dados[JOAO].capitulos[3].versos[17] = wxT("Porque Deus enviou o seu Filho ao mundo, não para que julgasse o mundo, mas para que o mundo fosse salvo por ele.");
    b->dados[JOAO].capitulos[3].versos[18] = wxT("Quem crê nele não é julgado; mas quem não crê, já está julgado; porquanto não crê no nome do unigênito Filho de Deus.");
    b->dados[JOAO].capitulos[3].versos[19] = wxT("E o julgamento é este: A luz veio ao mundo, e os homens amaram antes as trevas que a luz, porque as suas obras eram más.");
    b->dados[JOAO].capitulos[3].versos[20] = wxT("Porque todo aquele que faz o mal aborrece a luz, e não vem para a luz, para que as suas obras não sejam reprovadas.");
    b->dados[JOAO].capitulos[3].versos[21] = wxT("Mas quem pratica a verdade vem para a luz, a fim de que seja manifesto que as suas obras são feitas em Deus.");
    b->dados[JOAO].capitulos[3].versos[22] = wxT("Depois disto foi Jesus com seus discípulos para a terra da Judéia, onde se demorou com eles e batizava.");
    b->dados[JOAO].capitulos[3].versos[23] = wxT("Ora, João também estava batizando em Enom, perto de Salim, porque havia ali muitas águas; e o povo ia e se batizava.");
    b->dados[JOAO].capitulos[3].versos[24] = wxT("Pois João ainda não fora lançado no cárcere.");
    b->dados[JOAO].capitulos[3].versos[25] = wxT("Surgiu então uma contenda entre os discípulos de João e um judeu acerca da purificação.");
    b->dados[JOAO].capitulos[3].versos[26] = wxT("E foram ter com João e disseram-lhe: Rabi, aquele que estava contigo além do Jordão, do qual tens dado testemunho, eis que está batizando, e todos vão ter com ele.");
    b->dados[JOAO].capitulos[3].versos[27] = wxT("Respondeu João: O homem não pode receber coisa alguma, se não lhe for dada do céu.");
    b->dados[JOAO].capitulos[3].versos[28] = wxT("Vós mesmos me sois testemunhas de que eu disse: Não sou o Cristo, mas sou enviado adiante dele.");
    b->dados[JOAO].capitulos[3].versos[29] = wxT("Aquele que tem a noiva é o noivo; mas o amigo do noivo, que está presente e o ouve, regozija-se muito com a voz do noivo. Assim, pois, este meu gozo está completo.");
    b->dados[JOAO].capitulos[3].versos[30] = wxT("É necessário que ele cresça e que eu diminua.");
    b->dados[JOAO].capitulos[3].versos[31] = wxT("Aquele que vem de cima é sobre todos; aquele que vem da terra é da terra, e fala da terra. Aquele que vem do céu é sobre todos.");
    b->dados[JOAO].capitulos[3].versos[32] = wxT("Aquilo que ele tem visto e ouvido, isso testifica; e ninguém aceita o seu testemunho.");
    b->dados[JOAO].capitulos[3].versos[33] = wxT("Mas o que aceitar o seu testemunho, esse confirma que Deus é verdadeiro.");
    b->dados[JOAO].capitulos[3].versos[34] = wxT("Pois aquele que Deus enviou fala as palavras de Deus; porque Deus não dá o Espírito por medida.");
    b->dados[JOAO].capitulos[3].versos[35] = wxT("O Pai ama ao Filho, e todas as coisas entregou nas suas mãos.");
    b->dados[JOAO].capitulos[3].versos[36] = wxT("Quem crê no Filho tem a vida eterna; o que, porém, desobedece ao Filho não verá a vida, mas sobre ele permanece a ira de Deus.");

    b->dados[JOAO].capitulos[4].versos[1] = wxT("Quando, pois, o Senhor soube que os fariseus tinham ouvido dizer que ele, Jesus, fazia e batizava mais discípulos do que João");
    b->dados[JOAO].capitulos[4].versos[2] = wxT("{ainda que Jesus mesmo não batizava, mas os seus discípulos}");
    b->dados[JOAO].capitulos[4].versos[3] = wxT("deixou a Judéia, e foi outra vez para a Galiléia.");
    b->dados[JOAO].capitulos[4].versos[4] = wxT("E era-lhe necessário passar por Samária.");
    b->dados[JOAO].capitulos[4].versos[5] = wxT("Chegou, pois, a uma cidade de Samária, chamada Sicar, junto da herdade que Jacó dera a seu filho José;");
    b->dados[JOAO].capitulos[4].versos[6] = wxT("achava-se ali o poço de Jacó. Jesus, pois, cansado da viagem, sentou-se assim junto do poço; era cerca da hora sexta.");
    b->dados[JOAO].capitulos[4].versos[7] = wxT("Veio uma mulher de Samária tirar água. Disse-lhe Jesus: Dá-me de beber.");
    b->dados[JOAO].capitulos[4].versos[8] = wxT("Pois seus discípulos tinham ido à cidade comprar comida.");
    b->dados[JOAO].capitulos[4].versos[9] = wxT("Disse-lhe então a mulher samaritana: Como, sendo tu judeu, me pedes de beber a mim, que sou mulher samaritana? {Porque os judeus não se comunicavam com os samaritanos.}");
    b->dados[JOAO].capitulos[4].versos[10] = wxT("Respondeu-lhe Jesus: Se tivesses conhecido o dom de Deus e quem é o que te diz: Dá-me de beber, tu lhe terias pedido e ele te haveria dado água viva.");
    b->dados[JOAO].capitulos[4].versos[11] = wxT("Disse-lhe a mulher: Senhor, tu não tens com que tirá-la, e o poço é fundo; donde, pois, tens essa água viva?");
    b->dados[JOAO].capitulos[4].versos[12] = wxT("És tu, porventura, maior do que o nosso pai Jacó, que nos deu o poço, do qual também ele mesmo bebeu, e os filhos, e o seu gado?.");
    b->dados[JOAO].capitulos[4].versos[13] = wxT("Replicou-lhe Jesus: Todo o que beber desta água tornará a ter sede;");
    b->dados[JOAO].capitulos[4].versos[14] = wxT("mas aquele que beber da água que eu lhe der nunca terá sede; pelo contrário, a água que eu lhe der se fará nele uma fonte de água que jorre para a vida eterna.");
    b->dados[JOAO].capitulos[4].versos[15] = wxT("Disse-lhe a mulher: Senhor, dá-me dessa água, para que não mais tenha sede, nem venha aqui tirá-la.");
    b->dados[JOAO].capitulos[4].versos[16] = wxT("Disse-lhe Jesus: Vai, chama o teu marido e vem cá.");
    b->dados[JOAO].capitulos[4].versos[17] = wxT("Respondeu a mulher: Não tenho marido. Disse-lhe Jesus: Disseste bem: Não tenho marido;");
    b->dados[JOAO].capitulos[4].versos[18] = wxT("porque cinco maridos tiveste, e o que agora tens não é teu marido; isso disseste com verdade.");
    b->dados[JOAO].capitulos[4].versos[19] = wxT("Disse-lhe a mulher: Senhor, vejo que és profeta.");
    b->dados[JOAO].capitulos[4].versos[20] = wxT("Nossos pais adoraram neste monte, e vós dizeis que em Jerusalém é o lugar onde se deve adorar.");
    b->dados[JOAO].capitulos[4].versos[21] = wxT("Disse-lhe Jesus: Mulher, crê-me, a hora vem, em que nem neste monte, nem em Jerusalém adorareis o Pai.");
    b->dados[JOAO].capitulos[4].versos[22] = wxT("Vós adorais o que não conheceis; nós adoramos o que conhecemos; porque a salvação vem dos judeus.");
    b->dados[JOAO].capitulos[4].versos[23] = wxT("Mas a hora vem, e agora é, em que os verdadeiros adoradores adorarão o Pai em espírito e em verdade; porque o Pai procura a tais que assim o adorem.");
    b->dados[JOAO].capitulos[4].versos[24] = wxT("Deus é Espírito, e é necessário que os que o adoram o adorem em espírito e em verdade.");
    b->dados[JOAO].capitulos[4].versos[25] = wxT("Replicou-lhe a mulher: Eu sei que vem o Messias {que se chama o Cristo}; quando ele vier há de nos anunciar todas as coisas.");
    b->dados[JOAO].capitulos[4].versos[26] = wxT("Disse-lhe Jesus: Eu o sou, eu que falo contigo.");
    b->dados[JOAO].capitulos[4].versos[27] = wxT("E nisto vieram os seus discípulos, e se admiravam de que estivesse falando com uma mulher; todavia nenhum lhe perguntou: Que é que procuras? ou: Por que falas com ela?");
    b->dados[JOAO].capitulos[4].versos[28] = wxT("Deixou, pois, a mulher o seu cântaro, foi à cidade e disse àqueles homens:");
    b->dados[JOAO].capitulos[4].versos[29] = wxT("Vinde, vede um homem que me disse tudo quanto eu tenho feito; será este, porventura, o Cristo?");
    b->dados[JOAO].capitulos[4].versos[30] = wxT("Saíram, pois, da cidade e vinham ter com ele.");
    b->dados[JOAO].capitulos[4].versos[31] = wxT("Entrementes os seus discípulos lhe rogavam, dizendo: Rabi, come.");
    b->dados[JOAO].capitulos[4].versos[32] = wxT("Ele, porém, respondeu: Uma comida tenho para comer que vós não conheceis.");
    b->dados[JOAO].capitulos[4].versos[33] = wxT("Então os discípulos diziam uns aos outros: Acaso alguém lhe trouxe de comer?");
    b->dados[JOAO].capitulos[4].versos[34] = wxT("Disse-lhes Jesus: A minha comida é fazer a vontade daquele que me enviou, e completar a sua obra.");
    b->dados[JOAO].capitulos[4].versos[35] = wxT("Não dizeis vós: Ainda há quatro meses até que venha a ceifa? Ora, eu vos digo: levantai os vossos olhos, e vede os campos, que já estão brancos para a ceifa.");
    b->dados[JOAO].capitulos[4].versos[36] = wxT("Quem ceifa já está recebendo recompensa e ajuntando fruto para a vida eterna; para que o que semeia e o que ceifa juntamente se regozijem.");
    b->dados[JOAO].capitulos[4].versos[37] = wxT("Porque nisto é verdadeiro o ditado: Um é o que semeia, e outro o que ceifa.");
    b->dados[JOAO].capitulos[4].versos[38] = wxT("Eu vos enviei a ceifar onde não trabalhaste; outros trabalharam, e vós entrastes no seu trabalho.");
    b->dados[JOAO].capitulos[4].versos[39] = wxT("E muitos samaritanos daquela cidade creram nele, por causa da palavra da mulher, que testificava: Ele me disse tudo quanto tenho feito.");
    b->dados[JOAO].capitulos[4].versos[40] = wxT("Indo, pois, ter com ele os samaritanos, rogaram-lhe que ficasse com eles; e ficou ali dois dias.");
    b->dados[JOAO].capitulos[4].versos[41] = wxT("E muitos mais creram por causa da palavra dele;");
    b->dados[JOAO].capitulos[4].versos[42] = wxT("e diziam à mulher: Já não é pela tua palavra que nós cremos; pois agora nós mesmos temos ouvido e sabemos que este é verdadeiramente o Salvador do mundo.");
    b->dados[JOAO].capitulos[4].versos[43] = wxT("Passados os dois dias partiu dali para a Galiléia.");
    b->dados[JOAO].capitulos[4].versos[44] = wxT("Porque Jesus mesmo testificou que um profeta não recebe honra na sua própria pátria.");
    b->dados[JOAO].capitulos[4].versos[45] = wxT("Assim, pois, que chegou à Galiléia, os galileus o receberam, porque tinham visto todas as coisas que fizera em Jerusalém na ocasião da festa; pois também eles tinham ido à festa.");
    b->dados[JOAO].capitulos[4].versos[46] = wxT("Foi, então, outra vez a Caná da Galiléia, onde da água fizera vinho. Ora, havia um oficial do rei, cujo filho estava enfermo em Cafarnaum.");
    b->dados[JOAO].capitulos[4].versos[47] = wxT("Quando ele soube que Jesus tinha vindo da Judéia para a Galiléia, foi ter com ele, e lhe rogou que descesse e lhe curasse o filho; pois estava à morte.");
    b->dados[JOAO].capitulos[4].versos[48] = wxT("Então Jesus lhe disse: Se não virdes sinais e prodígios, de modo algum crereis.");
    b->dados[JOAO].capitulos[4].versos[49] = wxT("Rogou-lhe o oficial: Senhor, desce antes que meu filho morra.");
    b->dados[JOAO].capitulos[4].versos[50] = wxT("Respondeu-lhe Jesus: Vai, o teu filho vive. E o homem creu na palavra que Jesus lhe dissera, e partiu.");
    b->dados[JOAO].capitulos[4].versos[51] = wxT("Quando ele já ia descendo, saíram-lhe ao encontro os seus servos, e lhe disseram que seu filho vivia.");
    b->dados[JOAO].capitulos[4].versos[52] = wxT("Perguntou-lhes, pois, a que hora começara a melhorar; ao que lhe disseram: Ontem à hora sétima a febre o deixou.");
    b->dados[JOAO].capitulos[4].versos[53] = wxT("Reconheceu, pois, o pai ser aquela hora a mesma em que Jesus lhe dissera: O teu filho vive; e creu ele e toda a sua casa.");
    b->dados[JOAO].capitulos[4].versos[54] = wxT("Foi esta a segunda vez que Jesus, ao voltar da Judéia para a Galiléia, ali operou sinal.");

    b->dados[JOAO].capitulos[5].versos[1] = wxT("Depois disso havia uma festa dos judeus; e Jesus subiu a Jerusalém.");
    b->dados[JOAO].capitulos[5].versos[2] = wxT("Ora, em Jerusalém, próximo à porta das ovelhas, há um tanque, chamado em hebraico Betesda, o qual tem cinco alpendres.");
    b->dados[JOAO].capitulos[5].versos[3] = wxT("Nestes jazia grande multidão de enfermos, cegos, mancos e ressicados {esperando o movimento da água.}");
    b->dados[JOAO].capitulos[5].versos[4] = wxT("{Porquanto um anjo descia em certo tempo ao tanque, e agitava a água; então o primeiro que ali descia, depois do movimento da água, sarava de qualquer enfermidade que tivesse.}");
    b->dados[JOAO].capitulos[5].versos[5] = wxT("Achava-se ali um homem que, havia trinta e oito anos, estava enfermo.");
    b->dados[JOAO].capitulos[5].versos[6] = wxT("Jesus, vendo-o deitado e sabendo que estava assim havia muito tempo, perguntou-lhe: Queres ficar são?");
    b->dados[JOAO].capitulos[5].versos[7] = wxT("Respondeu-lhe o enfermo: Senhor, não tenho ninguém que, ao ser agitada a água, me ponha no tanque; assim, enquanto eu vou, desce outro antes de mim.");
    b->dados[JOAO].capitulos[5].versos[8] = wxT("Disse-lhe Jesus: Levanta-te, toma o teu leito e anda.");
    b->dados[JOAO].capitulos[5].versos[9] = wxT("Imediatamente o homem ficou são; e, tomando o seu leito, começou a andar. Ora, aquele dia era sábado.");
    b->dados[JOAO].capitulos[5].versos[10] = wxT("Pelo que disseram os judeus ao que fora curado: Hoje é sábado, e não te é lícito carregar o leito.");
    b->dados[JOAO].capitulos[5].versos[11] = wxT("Ele, porém, lhes respondeu: Aquele que me curou, esse mesmo me disse: Toma o teu leito e anda.");
    b->dados[JOAO].capitulos[5].versos[12] = wxT("Perguntaram-lhe, pois: Quem é o homem que te disse: Toma o teu leito e anda?");
    b->dados[JOAO].capitulos[5].versos[13] = wxT("Mas o que fora curado não sabia quem era; porque Jesus se retirara, por haver muita gente naquele lugar.");
    b->dados[JOAO].capitulos[5].versos[14] = wxT("Depois Jesus o encontrou no templo, e disse-lhe: Olha, já estás curado; não peques mais, para que não te suceda coisa pior.");
    b->dados[JOAO].capitulos[5].versos[15] = wxT("Retirou-se, então, o homem, e contou aos judeus que era Jesus quem o curara.");
    b->dados[JOAO].capitulos[5].versos[16] = wxT("Por isso os judeus perseguiram a Jesus, porque fazia estas coisas no sábado.");
    b->dados[JOAO].capitulos[5].versos[17] = wxT("Mas Jesus lhes respondeu: Meu Pai trabalha até agora, e eu trabalho também.");
    b->dados[JOAO].capitulos[5].versos[18] = wxT("Por isso, pois, os judeus ainda mais procuravam matá-lo, porque não só violava o sábado, mas também dizia que Deus era seu próprio Pai, fazendo-se igual a Deus.");
    b->dados[JOAO].capitulos[5].versos[19] = wxT("Disse-lhes, pois, Jesus: Em verdade, em verdade vos digo que o Filho de si mesmo nada pode fazer, senão o que vir o Pai fazer; porque tudo quanto ele faz, o Filho o faz igualmente.");
    b->dados[JOAO].capitulos[5].versos[20] = wxT("Porque o Pai ama ao Filho, e mostra-lhe tudo o que ele mesmo faz; e maiores obras do que estas lhe mostrará, para que vos maravilheis.");
    b->dados[JOAO].capitulos[5].versos[21] = wxT("Pois, assim como o Pai levanta os mortos e lhes dá vida, assim também o Filho dá vida a quem ele quer.");
    b->dados[JOAO].capitulos[5].versos[22] = wxT("Porque o Pai a ninguém julga, mas deu ao Filho todo o julgamento,");
    b->dados[JOAO].capitulos[5].versos[23] = wxT("para que todos honrem o Filho, assim como honram o Pai. Quem não honra o Filho, não honra o Pai que o enviou.");
    b->dados[JOAO].capitulos[5].versos[24] = wxT("Em verdade, em verdade vos digo que quem ouve a minha palavra, e crê naquele que me enviou, tem a vida eterna e não entra em juízo, mas já passou da morte para a vida.");
    b->dados[JOAO].capitulos[5].versos[25] = wxT("Em verdade, em verdade vos digo que vem a hora, e agora é, em que os mortos ouvirão a voz do Filho de Deus, e os que a ouvirem viverão.");
    b->dados[JOAO].capitulos[5].versos[26] = wxT("Pois assim como o Pai tem vida em si mesmo, assim também deu ao Filho ter vida em si mesmos;");
    b->dados[JOAO].capitulos[5].versos[27] = wxT("e deu-lhe autoridade para julgar, porque é o Filho do homem.");
    b->dados[JOAO].capitulos[5].versos[28] = wxT("Não vos admireis disso, porque vem a hora em que todos os que estão nos sepulcros ouvirão a sua voz e sairão:");
    b->dados[JOAO].capitulos[5].versos[29] = wxT("os que tiverem feito o bem, para a ressurreição da vida, e os que tiverem praticado o mal, para a ressurreição do juízo.");
    b->dados[JOAO].capitulos[5].versos[30] = wxT("Eu não posso de mim mesmo fazer coisa alguma; como ouço, assim julgo; e o meu juízo é justo, porque não procuro a minha vontade, mas a vontade daquele que me enviou.");
    b->dados[JOAO].capitulos[5].versos[31] = wxT("Se eu der testemunho de mim mesmo, o meu testemunho não é verdadeiro.");
    b->dados[JOAO].capitulos[5].versos[32] = wxT("Outro é quem dá testemunho de mim; e sei que o testemunho que ele dá de mim é verdadeiro.");
    b->dados[JOAO].capitulos[5].versos[33] = wxT("Vós mandastes mensageiros a João, e ele deu testemunho da verdade;");
    b->dados[JOAO].capitulos[5].versos[34] = wxT("eu, porém, não recebo testemunho de homem; mas digo isto para que sejais salvos.");
    b->dados[JOAO].capitulos[5].versos[35] = wxT("Ele era a lâmpada que ardia e alumiava; e vós quisestes alegrar-vos por um pouco de tempo com a sua luz.");
    b->dados[JOAO].capitulos[5].versos[36] = wxT("Mas o testemunho que eu tenho é maior do que o de João; porque as obras que o Pai me deu para realizar, as mesmas obras que faço dão testemunho de mim que o Pai me enviou.");
    b->dados[JOAO].capitulos[5].versos[37] = wxT("E o Pai que me enviou, ele mesmo tem dado testemunho de mim. Vós nunca ouvistes a sua voz, nem vistes a sua forma;");
    b->dados[JOAO].capitulos[5].versos[38] = wxT("e a sua palavra não permanece em vós; porque não credes naquele que ele enviou.");
    b->dados[JOAO].capitulos[5].versos[39] = wxT("Examinais as Escrituras, porque julgais ter nelas a vida eterna; e são elas que dão testemunho de mim;");
    b->dados[JOAO].capitulos[5].versos[40] = wxT("mas não quereis vir a mim para terdes vida!");
    b->dados[JOAO].capitulos[5].versos[41] = wxT("Eu não recebo glória da parte dos homens;");
    b->dados[JOAO].capitulos[5].versos[42] = wxT("mas bem vos conheço, que não tendes em vós o amor de Deus.");
    b->dados[JOAO].capitulos[5].versos[43] = wxT("Eu vim em nome de meu Pai, e não me recebeis; se outro vier em seu próprio nome, a esse recebereis.");
    b->dados[JOAO].capitulos[5].versos[44] = wxT("Como podeis crer, vós que recebeis glória uns dos outros e não buscais a glória que vem do único Deus?");
    b->dados[JOAO].capitulos[5].versos[45] = wxT("Não penseis que eu vos hei de acusar perante o Pai. Há um que vos acusa, Moisés, em quem vós esperais.");
    b->dados[JOAO].capitulos[5].versos[46] = wxT("Pois se crêsseis em Moisés, creríeis em mim; porque de mim ele escreveu.");
    b->dados[JOAO].capitulos[5].versos[47] = wxT("Mas, se não credes nos escritos, como crereis nas minhas palavras?");

    b->dados[JOAO].capitulos[6].versos[1] = wxT("Depois disto partiu Jesus para o outro lado do mar da Galiléia, também chamado de Tiberíades.");
    b->dados[JOAO].capitulos[6].versos[2] = wxT("E seguia-o uma grande multidão, porque via os sinais que operava sobre os enfermos.");
    b->dados[JOAO].capitulos[6].versos[3] = wxT("Subiu, pois, Jesus ao monte e sentou-se ali com seus discípulos.");
    b->dados[JOAO].capitulos[6].versos[4] = wxT("Ora, a páscoa, a festa dos judeus, estava próxima.");
    b->dados[JOAO].capitulos[6].versos[5] = wxT("Então Jesus, levantando os olhos, e vendo que uma grande multidão vinha ter com ele, disse a Felipe: Onde compraremos pão, para estes comerem?");
    b->dados[JOAO].capitulos[6].versos[6] = wxT("Mas dizia isto para o experimentar; pois ele bem sabia o que ia fazer.");
    b->dados[JOAO].capitulos[6].versos[7] = wxT("Respondeu-lhe Felipe: Duzentos denários de pão não lhes bastam, para que cada um receba um pouco.");
    b->dados[JOAO].capitulos[6].versos[8] = wxT("Ao que lhe disse um dos seus discípulos, André, irmão de Simão Pedro:");
    b->dados[JOAO].capitulos[6].versos[9] = wxT("Está aqui um rapaz que tem cinco pães de cevada e dois peixinhos; mas que é isto para tantos?");
    b->dados[JOAO].capitulos[6].versos[10] = wxT("Disse Jesus: Fazei reclinar-se o povo. Ora, naquele lugar havia muita relva. Reclinaram-se aí, pois, os homens em número de quase cinco mil.");
    b->dados[JOAO].capitulos[6].versos[11] = wxT("Jesus, então, tomou os pães e, havendo dado graças, repartiu-os pelos que estavam reclinados; e de igual modo os peixes, quanto eles queriam.");
    b->dados[JOAO].capitulos[6].versos[12] = wxT("E quando estavam saciados, disse aos seus discípulos: Recolhei os pedaços que sobejaram, para que nada se perca.");
    b->dados[JOAO].capitulos[6].versos[13] = wxT("Recolheram-nos, pois e encheram doze cestos de pedaços dos cinco pães de cevada, que sobejaram aos que haviam comido.");
    b->dados[JOAO].capitulos[6].versos[14] = wxT("Vendo, pois, aqueles homens o sinal que Jesus operara, diziam: este é verdadeiramente o profeta que havia de vir ao mundo.");
    b->dados[JOAO].capitulos[6].versos[15] = wxT("Percebendo, pois, Jesus que estavam prestes a vir e levá-lo à força para o fazerem rei, tornou a retirar-se para o monte, ele sozinho.");
    b->dados[JOAO].capitulos[6].versos[16] = wxT("Ao cair da tarde, desceram os seus discípulos ao mar;");
    b->dados[JOAO].capitulos[6].versos[17] = wxT("e, entrando num barco, atravessavam o mar em direção a Cafarnaum; enquanto isso, escurecera e Jesus ainda não tinha vindo ter com eles;");
    b->dados[JOAO].capitulos[6].versos[18] = wxT("ademais, o mar se empolava, porque soprava forte vento.");
    b->dados[JOAO].capitulos[6].versos[19] = wxT("Tendo, pois, remado uns vinte e cinco ou trinta estádios, viram a Jesus andando sobre o mar e aproximando-se do barco; e ficaram atemorizados.");
    b->dados[JOAO].capitulos[6].versos[20] = wxT("Mas ele lhes disse: Sou eu; não temais.");
    b->dados[JOAO].capitulos[6].versos[21] = wxT("Então eles de boa mente o receberam no barco; e logo o barco chegou à terra para onde iam.");
    b->dados[JOAO].capitulos[6].versos[22] = wxT("No dia seguinte, a multidão que ficara no outro lado do mar, sabendo que não houvera ali senão um barquinho, e que Jesus não embarcara nele com seus discípulos, mas que estes tinham ido sós");
    b->dados[JOAO].capitulos[6].versos[23] = wxT("{contudo, outros barquinhos haviam chegado a Tiberíades para perto do lugar onde comeram o pão, havendo o Senhor dado graças};");
    b->dados[JOAO].capitulos[6].versos[24] = wxT("quando, pois, viram que Jesus não estava ali nem os seus discípulos, entraram eles também nos barcos, e foram a Cafarnaum, em busca de Jesus.");
    b->dados[JOAO].capitulos[6].versos[25] = wxT("E, achando-o no outro lado do mar, perguntaram-lhe: Rabi, quando chegaste aqui?");
    b->dados[JOAO].capitulos[6].versos[26] = wxT("Respondeu-lhes Jesus: Em verdade, em verdade vos digo que me buscais, não porque vistes sinais, mas porque comestes do pão e vos saciastes.");
    b->dados[JOAO].capitulos[6].versos[27] = wxT("Trabalhai, não pela comida que perece, mas pela comida que permanece para a vida eterna, a qual o Filho do homem vos dará; pois neste, Deus, o Pai, imprimiu o seu selo.");
    b->dados[JOAO].capitulos[6].versos[28] = wxT("Pergutaram-lhe, pois: Que havemos de fazer para praticarmos as obras de Deus?");
    b->dados[JOAO].capitulos[6].versos[29] = wxT("Jesus lhes respondeu: A obra de Deus é esta: Que creiais naquele que ele enviou.");
    b->dados[JOAO].capitulos[6].versos[30] = wxT("Perguntaram-lhe, então: Que sinal, pois, fazes tu, para que o vejamos e te creiamos? Que operas tu?");
    b->dados[JOAO].capitulos[6].versos[31] = wxT("Nossos pais comeram o maná no deserto, como está escrito: Do céu deu-lhes pão a comer.");
    b->dados[JOAO].capitulos[6].versos[32] = wxT("Respondeu-lhes Jesus: Em verdade, em verdade vos digo: Não foi Moisés que vos deu o pão do céu; mas meu Pai vos dá o verdadeiro pão do céu.");
    b->dados[JOAO].capitulos[6].versos[33] = wxT("Porque o pão de Deus é aquele que desce do céu e dá vida ao mundo.");
    b->dados[JOAO].capitulos[6].versos[34] = wxT("Disseram-lhe, pois: Senhor, dá-nos sempre desse pão.");
    b->dados[JOAO].capitulos[6].versos[35] = wxT("Declarou-lhes Jesus. Eu sou o pão da vida; aquele que vem a mim, de modo algum terá fome, e quem crê em mim jamais terá sede.");
    b->dados[JOAO].capitulos[6].versos[36] = wxT("Mas como já vos disse, vós me tendes visto, e contudo não credes.");
    b->dados[JOAO].capitulos[6].versos[37] = wxT("Todo o que o Pai me dá virá a mim; e o que vem a mim de maneira nenhuma o lançarei fora.");
    b->dados[JOAO].capitulos[6].versos[38] = wxT("Porque eu desci do céu, não para fazer a minha vontade, mas a vontade daquele que me enviou.");
    b->dados[JOAO].capitulos[6].versos[39] = wxT("E a vontade do que me enviou é esta: Que eu não perca nenhum de todos aqueles que me deu, mas que eu o ressuscite no último dia.");
    b->dados[JOAO].capitulos[6].versos[40] = wxT("Porquanto esta é a vontade de meu Pai: Que todo aquele que vê o Filho e crê nele, tenha a vida eterna; e eu o ressuscitarei no último dia.");
    b->dados[JOAO].capitulos[6].versos[41] = wxT("Murmuravam, pois, dele os judeus, porque dissera: Eu sou o pão que desceu do céu;");
    b->dados[JOAO].capitulos[6].versos[42] = wxT("e perguntavam: Não é Jesus, o filho de José, cujo pai e mãe nós conhecemos? Como, pois, diz agora: Desci do céu?");
    b->dados[JOAO].capitulos[6].versos[43] = wxT("Respondeu-lhes Jesus: Não murmureis entre vós.");
    b->dados[JOAO].capitulos[6].versos[44] = wxT("Ninguém pode vir a mim, se o Pai que me enviou não o trouxer; e eu o ressuscitarei no último dia.");
    b->dados[JOAO].capitulos[6].versos[45] = wxT("Está escrito nos profetas: E serão todos ensinados por Deus. Portanto todo aquele que do Pai ouviu e aprendeu vem a mim.");
    b->dados[JOAO].capitulos[6].versos[46] = wxT("Não que alguém tenha visto o Pai, senão aquele que é vindo de Deus; só ele tem visto o Pai.");
    b->dados[JOAO].capitulos[6].versos[47] = wxT("Em verdade, em verdade vos digo: Aquele que crê tem a vida eterna.");
    b->dados[JOAO].capitulos[6].versos[48] = wxT("Eu sou o pão da vida.");
    b->dados[JOAO].capitulos[6].versos[49] = wxT("Vossos pais comeram o maná no deserto e morreram.");
    b->dados[JOAO].capitulos[6].versos[50] = wxT("Este é o pão que desce do céu, para que o que dele comer não morra.");
    b->dados[JOAO].capitulos[6].versos[51] = wxT("Eu sou o pão vivo que desceu do céu; se alguém comer deste pão, viverá para sempre; e o pão que eu darei pela vida do mundo é a minha carne.");
    b->dados[JOAO].capitulos[6].versos[52] = wxT("Disputavam, pois, os judeus entre si, dizendo: Como pode este dar-nos a sua carne a comer?");
    b->dados[JOAO].capitulos[6].versos[53] = wxT("Disse-lhes Jesus: Em verdade, em verdade vos digo: Se não comerdes a carne do Filho do homem, e não beberdes o seu sangue, não tereis vida em vós mesmos.");
    b->dados[JOAO].capitulos[6].versos[54] = wxT("Quem come a minha carne e bebe o meu sangue tem a vida eterna; e eu o ressuscitarei no último dia.");
    b->dados[JOAO].capitulos[6].versos[55] = wxT("Porque a minha carne verdadeiramente é comida, e o meu sangue verdadeiramente é bebida.");
    b->dados[JOAO].capitulos[6].versos[56] = wxT("Quem come a minha carne e bebe o meu sangue permanece em mim e eu nele.");
    b->dados[JOAO].capitulos[6].versos[57] = wxT("Assim como o Pai, que vive, me enviou, e eu vivo pelo Pai, assim, quem de mim se alimenta, também viverá por mim.");
    b->dados[JOAO].capitulos[6].versos[58] = wxT("Este é o pão que desceu do céu; não é como o caso de vossos pais, que comeram o maná e morreram; quem comer este pão viverá para sempre.");
    b->dados[JOAO].capitulos[6].versos[59] = wxT("Estas coisas falou Jesus quando ensinava na sinagoga em Cafarnaum.");
    b->dados[JOAO].capitulos[6].versos[60] = wxT("Muitos, pois, dos seus discípulos, ouvindo isto, disseram: Duro é este discurso; quem o pode ouvir?");
    b->dados[JOAO].capitulos[6].versos[61] = wxT("Mas, sabendo Jesus em si mesmo que murmuravam disto os seus discípulos, disse-lhes: Isto vos escandaliza?");
    b->dados[JOAO].capitulos[6].versos[62] = wxT("Que seria, pois, se vísseis subir o Filho do homem para onde primeiro estava?");
    b->dados[JOAO].capitulos[6].versos[63] = wxT("O espírito é o que vivifica, a carne para nada aproveita; as palavras que eu vos tenho dito são espírito e são vida.");
    b->dados[JOAO].capitulos[6].versos[64] = wxT("Mas há alguns de vós que não crêem. Pois Jesus sabia, desde o princípio, quem eram os que não criam, e quem era o que o havia de entregar.");
    b->dados[JOAO].capitulos[6].versos[65] = wxT("E continuou: Por isso vos disse que ninguém pode vir a mim, se pelo Pai lhe não for concedido.");
    b->dados[JOAO].capitulos[6].versos[66] = wxT("Por causa disso muitos dos seus discípulos voltaram para trás e não andaram mais com ele.");
    b->dados[JOAO].capitulos[6].versos[67] = wxT("Perguntou então Jesus aos doze: Quereis vós também retirar-vos?");
    b->dados[JOAO].capitulos[6].versos[68] = wxT("Respondeu-lhe Simão Pedro: Senhor, para quem iremos nós? Tu tens as palavras da vida eterna.");
    b->dados[JOAO].capitulos[6].versos[69] = wxT("E nós já temos crido e bem sabemos que tu és o Santo de Deus.");
    b->dados[JOAO].capitulos[6].versos[70] = wxT("Respondeu-lhes Jesus: Não vos escolhi a vós os doze? Contudo um de vós é o diabo.");
    b->dados[JOAO].capitulos[6].versos[71] = wxT("Referia-se a Judas, filho de Simão Iscariotes; porque era ele o que o havia de entregar, sendo um dos doze.");

    b->dados[JOAO].capitulos[7].versos[1] = wxT("Depois disto andava Jesus pela Galiléia; pois não queria andar pela Judéia, porque os judeus procuravam matá-lo.");
    b->dados[JOAO].capitulos[7].versos[2] = wxT("Ora, estava próxima a festa dos judeus, a dos tabernáculos.");
    b->dados[JOAO].capitulos[7].versos[3] = wxT("Disseram-lhe, então, seus irmãos: Retira-te daqui e vai para a Judéia, para que também os teus discípulos vejam as obras que fazes.");
    b->dados[JOAO].capitulos[7].versos[4] = wxT("Porque ninguém faz coisa alguma em oculto, quando procura ser conhecido. Já que fazes estas coisas, manifesta-te ao mundo.");
    b->dados[JOAO].capitulos[7].versos[5] = wxT("Pois nem seus irmãos criam nele.");
    b->dados[JOAO].capitulos[7].versos[6] = wxT("Disse-lhes, então, Jesus: Ainda não é chegado o meu tempo; mas o vosso tempo sempre está presente.");
    b->dados[JOAO].capitulos[7].versos[7] = wxT("O mundo não vos pode odiar; mas ele me odeia a mim, porquanto dele testifico que as suas obras são más.");
    b->dados[JOAO].capitulos[7].versos[8] = wxT("Subi vós à festa; eu não subo ainda a esta festa, porque ainda não é chegado o meu tempo.");
    b->dados[JOAO].capitulos[7].versos[9] = wxT("E, havendo-lhes dito isto, ficou na Galiléia.");
    b->dados[JOAO].capitulos[7].versos[10] = wxT("Mas quando seus irmãos já tinham subido à festa, então subiu ele também, não publicamente, mas como em secreto.");
    b->dados[JOAO].capitulos[7].versos[11] = wxT("Ora, os judeus o procuravam na festa, e perguntavam: Onde está ele?");
    b->dados[JOAO].capitulos[7].versos[12] = wxT("E era grande a murmuração a respeito dele entre as multidões. Diziam alguns: Ele é bom. Mas outros diziam: não, antes engana o povo.");
    b->dados[JOAO].capitulos[7].versos[13] = wxT("Todavia ninguém falava dele abertamente, por medo dos judeus.");
    b->dados[JOAO].capitulos[7].versos[14] = wxT("Estando, pois, a festa já em meio, subiu Jesus ao templo e começou a ensinar.");
    b->dados[JOAO].capitulos[7].versos[15] = wxT("Então os judeus se admiravam, dizendo: Como sabe este letras, sem ter estudado?");
    b->dados[JOAO].capitulos[7].versos[16] = wxT("Respondeu-lhes Jesus: A minha doutrina não é minha, mas daquele que me enviou.");
    b->dados[JOAO].capitulos[7].versos[17] = wxT("Se alguém quiser fazer a vontade de Deus, há de saber se a doutrina é dele, ou se eu falo por mim mesmo.");
    b->dados[JOAO].capitulos[7].versos[18] = wxT("Quem fala por si mesmo busca a sua própria glória; mas o que busca a glória daquele que o enviou, esse é verdadeiro, e não há nele injustiça.");
    b->dados[JOAO].capitulos[7].versos[19] = wxT("Não vos deu Moisés a lei? no entanto nenhum de vós cumpre a lei. Por que procurais matar-me?");
    b->dados[JOAO].capitulos[7].versos[20] = wxT("Respondeu a multidão: Tens demônio; quem procura matar-te?");
    b->dados[JOAO].capitulos[7].versos[21] = wxT("Replicou-lhes Jesus: Uma só obra fiz, e todos vós admirais por causa disto.");
    b->dados[JOAO].capitulos[7].versos[22] = wxT("Moisés vos ordenou a circuncisão {não que fosse de Moisés, mas dos pais}, e no sábado circuncidais um homem.");
    b->dados[JOAO].capitulos[7].versos[23] = wxT("Ora, se um homem recebe a circuncisão no sábado, para que a lei de Moisés não seja violada, como vos indignais contra mim, porque no sábado tornei um homem inteiramente são?");
    b->dados[JOAO].capitulos[7].versos[24] = wxT("Não julgueis pela aparência mas julgai segundo o reto juízo.");
    b->dados[JOAO].capitulos[7].versos[25] = wxT("Diziam então alguns dos de Jerusalém: Não é este o que procuram matar?");
    b->dados[JOAO].capitulos[7].versos[26] = wxT("E eis que ele está falando abertamente, e nada lhe dizem. Será que as autoridades realmente o reconhecem como o Cristo?");
    b->dados[JOAO].capitulos[7].versos[27] = wxT("Entretanto sabemos donde este é; mas, quando vier o Cristo, ninguém saberá donde ele é.");
    b->dados[JOAO].capitulos[7].versos[28] = wxT("Jesus, pois, levantou a voz no templo e ensinava, dizendo: Sim, vós me conheceis, e sabeis donde sou; contudo eu não vim de mim mesmo, mas aquele que me enviou é verdadeiro, o qual vós não conheceis.");
    b->dados[JOAO].capitulos[7].versos[29] = wxT("Mas eu o conheço, porque dele venho, e ele me enviou.");
    b->dados[JOAO].capitulos[7].versos[30] = wxT("Procuravam, pois, prendê-lo; mas ninguém lhe deitou as mãos, porque ainda não era chegada a sua hora.");
    b->dados[JOAO].capitulos[7].versos[31] = wxT("Contudo muitos da multidão creram nele, e diziam: Será que o Cristo, quando vier, fará mais sinais do que este tem feito?");
    b->dados[JOAO].capitulos[7].versos[32] = wxT("Os fariseus ouviram a multidão murmurar estas coisas a respeito dele; e os principais sacerdotes e os fariseus mandaram guardas para o prenderem.");
    b->dados[JOAO].capitulos[7].versos[33] = wxT("Disse, pois, Jesus: Ainda um pouco de tempo estou convosco, e depois vou para aquele que me enviou.");
    b->dados[JOAO].capitulos[7].versos[34] = wxT("Vós me buscareis, e não me achareis; e onde eu estou, vós não podeis vir.");
    b->dados[JOAO].capitulos[7].versos[35] = wxT("Disseram, pois, os judeus uns aos outros: Para onde irá ele, que não o acharemos? Irá, porventura, à Dispersão entre os gregos, e ensinará os gregos?");
    b->dados[JOAO].capitulos[7].versos[36] = wxT("Que palavra é esta que disse: Buscar-me-eis, e não me achareis; e, Onde eu estou, vós não podeis vir?");
    b->dados[JOAO].capitulos[7].versos[37] = wxT("Ora, no seu último dia, o grande dia da festa, Jesus pôs-se em pé e clamou, dizendo: Se alguém tem sede, venha a mim e beba.");
    b->dados[JOAO].capitulos[7].versos[38] = wxT("Quem crê em mim, como diz a Escritura, do seu interior correrão rios de água viva.");
    b->dados[JOAO].capitulos[7].versos[39] = wxT("Ora, isto ele disse a respeito do Espírito que haviam de receber os que nele cressem; pois o Espírito ainda não fora dado, porque Jesus ainda não tinha sido glorificado.");
    b->dados[JOAO].capitulos[7].versos[40] = wxT("Então alguns dentre o povo, ouvindo essas palavras, diziam: Verdadeiramente este é o profeta.");
    b->dados[JOAO].capitulos[7].versos[41] = wxT("Outros diziam: Este é o Cristo; mas outros replicavam: Vem, pois, o Cristo da Galiléia?");
    b->dados[JOAO].capitulos[7].versos[42] = wxT("Não diz a Escritura que o Cristo vem da descendência de Davi, e de Belém, a aldeia donde era Davi?");
    b->dados[JOAO].capitulos[7].versos[43] = wxT("Assim houve uma dissensão entre o povo por causa dele.");
    b->dados[JOAO].capitulos[7].versos[44] = wxT("Alguns deles queriam prendê-lo; mas ninguém lhe pôs as mãos.");
    b->dados[JOAO].capitulos[7].versos[45] = wxT("Os guardas, pois, foram ter com os principais dos sacerdotes e fariseus, e estes lhes perguntaram: Por que não o trouxestes?");
    b->dados[JOAO].capitulos[7].versos[46] = wxT("Responderam os guardas: Nunca homem algum falou assim como este homem.");
    b->dados[JOAO].capitulos[7].versos[47] = wxT("Replicaram-lhes, pois, os fariseus: Também vós fostes enganados?");
    b->dados[JOAO].capitulos[7].versos[48] = wxT("Creu nele porventura alguma das autoridades, ou alguém dentre os fariseus?");
    b->dados[JOAO].capitulos[7].versos[49] = wxT("Mas esta multidão, que não sabe a lei, é maldita.");
    b->dados[JOAO].capitulos[7].versos[50] = wxT("Nicodemos, um deles, que antes fora ter com Jesus, perguntou-lhes:");
    b->dados[JOAO].capitulos[7].versos[51] = wxT("A nossa lei, porventura, julga um homem sem primeiro ouvi-lo e ter conhecimento do que ele faz?");
    b->dados[JOAO].capitulos[7].versos[52] = wxT("Responderam-lhe eles: És tu também da Galiléia? Examina e vê que da Galiléia não surge profeta.");
    b->dados[JOAO].capitulos[7].versos[53] = wxT("{E cada um foi para sua casa.}");

    b->dados[JOAO].capitulos[8].versos[1] = wxT("Mas Jesus foi para o Monte das Oliveiras.");
    b->dados[JOAO].capitulos[8].versos[2] = wxT("Pela manhã cedo voltou ao templo, e todo o povo vinha ter com ele; e Jesus, sentando-se o ensinava.");
    b->dados[JOAO].capitulos[8].versos[3] = wxT("Então os escribas e fariseus trouxeram-lhe uma mulher apanhada em adultério; e pondo-a no meio,");
    b->dados[JOAO].capitulos[8].versos[4] = wxT("disseram-lhe: Mestre, esta mulher foi apanhada em flagrante adultério.");
    b->dados[JOAO].capitulos[8].versos[5] = wxT("Ora, Moisés nos ordena na lei que as tais sejam apedrejadas. Tu, pois, que dizes?");
    b->dados[JOAO].capitulos[8].versos[6] = wxT("Isto diziam eles, tentando-o, para terem de que o acusar. Jesus, porém, inclinando-se, começou a escrever no chão com o dedo.");
    b->dados[JOAO].capitulos[8].versos[7] = wxT("Mas, como insistissem em perguntar-lhe, ergueu-se e disse-lhes: Aquele dentre vós que está sem pecado seja o primeiro que lhe atire uma pedra.");
    b->dados[JOAO].capitulos[8].versos[8] = wxT("E, tornando a inclinar-se, escrevia na terra.");
    b->dados[JOAO].capitulos[8].versos[9] = wxT("Quando ouviram isto foram saindo um a um, a começar pelos mais velhos, até os últimos; ficou só Jesus, e a mulher ali em pé.");
    b->dados[JOAO].capitulos[8].versos[10] = wxT("Então, erguendo-se Jesus e não vendo a ninguém senão a mulher, perguntou-lhe: Mulher, onde estão aqueles teus acusadores? Ninguém te condenou?");
    b->dados[JOAO].capitulos[8].versos[11] = wxT("Respondeu ela: Ninguém, Senhor. E disse-lhe Jesus: Nem eu te condeno; vai-te, e não peques mais.");
    b->dados[JOAO].capitulos[8].versos[12] = wxT("Então Jesus tornou a falar-lhes, dizendo: Eu sou a luz do mundo; quem me segue de modo algum andará em trevas, mas terá a luz da vida.");
    b->dados[JOAO].capitulos[8].versos[13] = wxT("Disseram-lhe, pois, os fariseus: Tu dás testemunho de ti mesmo; o teu testemunho não é verdadeiro.");
    b->dados[JOAO].capitulos[8].versos[14] = wxT("Respondeu-lhes Jesus: Ainda que eu dou testemunho de mim mesmo, o meu testemunho é verdadeiro; porque sei donde vim, e para onde vou; mas vós não sabeis donde venho, nem para onde vou.");
    b->dados[JOAO].capitulos[8].versos[15] = wxT("Vós julgais segundo a carne; eu a ninguém julgo.");
    b->dados[JOAO].capitulos[8].versos[16] = wxT("E, mesmo que eu julgue, o meu juízo é verdadeiro; porque não sou eu só, mas eu e o Pai que me enviou.");
    b->dados[JOAO].capitulos[8].versos[17] = wxT("Ora, na vossa lei está escrito que o testemunho de dois homens é verdadeiro.");
    b->dados[JOAO].capitulos[8].versos[18] = wxT("Sou eu que dou testemunho de mim mesmo, e o Pai que me enviou, também dá testemunho de mim.");
    b->dados[JOAO].capitulos[8].versos[19] = wxT("Perguntavam-lhe, pois: Onde está teu pai? Jesus respondeu: Não me conheceis a mim, nem a meu Pai; se vós me conhecêsseis a mim, também conheceríeis a meu Pai.");
    b->dados[JOAO].capitulos[8].versos[20] = wxT("Essas palavras proferiu Jesus no lugar do tesouro, quando ensinava no templo; e ninguém o prendeu, porque ainda não era chegada a sua hora.");
    b->dados[JOAO].capitulos[8].versos[21] = wxT("Disse-lhes, pois, Jesus outra vez: Eu me retiro; buscar-me-eis, e morrereis no vosso pecado. Para onde eu vou, vós não podeis ir.");
    b->dados[JOAO].capitulos[8].versos[22] = wxT("Então diziam os judeus: Será que ele vai suicidar-se, pois diz: Para onde eu vou, vós não podeis ir?");
    b->dados[JOAO].capitulos[8].versos[23] = wxT("Disse-lhes ele: Vós sois de baixo, eu sou de cima; vós sois deste mundo, eu não sou deste mundo.");
    b->dados[JOAO].capitulos[8].versos[24] = wxT("Por isso vos disse que morrereis em vossos pecados; porque, se não crerdes que eu sou, morrereis em vossos pecados.");
    b->dados[JOAO].capitulos[8].versos[25] = wxT("Perguntavam-lhe então: Quem és tu? Respondeu-lhes Jesus: Exatamente o que venho dizendo que sou.");
    b->dados[JOAO].capitulos[8].versos[26] = wxT("Muitas coisas tenho que dizer e julgar acerca de vós; mas aquele que me enviou é verdadeiro; e o que dele ouvi, isso falo ao mundo.");
    b->dados[JOAO].capitulos[8].versos[27] = wxT("Eles não perceberam que lhes falava do Pai.");
    b->dados[JOAO].capitulos[8].versos[28] = wxT("Prosseguiu, pois, Jesus: Quando tiverdes levantado o Filho do homem, então conhecereis que eu sou, e que nada faço de mim mesmo; mas como o Pai me ensinou, assim falo.");
    b->dados[JOAO].capitulos[8].versos[29] = wxT("E aquele que me enviou está comigo; não me tem deixado só; porque faço sempre o que é do seu agrado.");
    b->dados[JOAO].capitulos[8].versos[30] = wxT("Falando ele estas coisas, muitos creram nele.");
    b->dados[JOAO].capitulos[8].versos[31] = wxT("Dizia, pois, Jesus aos judeus que nele creram: Se vós permanecerdes na minha palavra, verdadeiramente sois meus discípulos;");
    b->dados[JOAO].capitulos[8].versos[32] = wxT("e conhecereis a verdade, e a verdade vos libertará.");
    b->dados[JOAO].capitulos[8].versos[33] = wxT("Responderam-lhe: Somos descendentes de Abraão, e nunca fomos escravos de ninguém; como dizes tu: Sereis livres?");
    b->dados[JOAO].capitulos[8].versos[34] = wxT("Replicou-lhes Jesus: Em verdade, em verdade vos digo que todo aquele que comete pecado é escravo do pecado.");
    b->dados[JOAO].capitulos[8].versos[35] = wxT("Ora, o escravo não fica para sempre na casa; o filho fica para sempre.");
    b->dados[JOAO].capitulos[8].versos[36] = wxT("Se, pois, o Filho vos libertar, verdadeiramente sereis livres.");
    b->dados[JOAO].capitulos[8].versos[37] = wxT("Bem sei que sois descendência de Abraão; contudo, procurais matar-me, porque a minha palavra não encontra lugar em vós.");
    b->dados[JOAO].capitulos[8].versos[38] = wxT("Eu falo do que vi junto de meu Pai; e vós fazeis o que também ouvistes de vosso pai.");
    b->dados[JOAO].capitulos[8].versos[39] = wxT("Responderam-lhe: Nosso pai é Abraão. Disse-lhes Jesus: Se sois filhos de Abraão, fazei as obras de Abraão.");
    b->dados[JOAO].capitulos[8].versos[40] = wxT("Mas agora procurais matar-me, a mim que vos falei a verdade que de Deus ouvi; isso Abraão não fez.");
    b->dados[JOAO].capitulos[8].versos[41] = wxT("Vós fazeis as obras de vosso pai. Replicaram-lhe eles: Nós não somos nascidos de prostituição; temos um Pai, que é Deus.");
    b->dados[JOAO].capitulos[8].versos[42] = wxT("Respondeu-lhes Jesus: Se Deus fosse o vosso Pai, vós me amaríeis, porque eu saí e vim de Deus; pois não vim de mim mesmo, mas ele me enviou.");
    b->dados[JOAO].capitulos[8].versos[43] = wxT("Por que não compreendeis a minha linguagem? é porque não podeis ouvir a minha palavra.");
    b->dados[JOAO].capitulos[8].versos[44] = wxT("Vós tendes por pai o Diabo, e quereis satisfazer os desejos de vosso pai; ele é homicida desde o princípio, e nunca se firmou na verdade, porque nele não há verdade; quando ele profere mentira, fala do que lhe é próprio; porque é mentiroso, e pai da mentira.");
    b->dados[JOAO].capitulos[8].versos[45] = wxT("Mas porque eu digo a verdade, não me credes.");
    b->dados[JOAO].capitulos[8].versos[46] = wxT("Quem dentre vós me convence de pecado? Se digo a verdade, por que não me credes?");
    b->dados[JOAO].capitulos[8].versos[47] = wxT("Quem é de Deus ouve as palavras de Deus; por isso vós não as ouvis, porque não sois de Deus.");
    b->dados[JOAO].capitulos[8].versos[48] = wxT("Responderam-lhe os judeus: Não dizemos com razão que és samaritano, e que tens demônio?");
    b->dados[JOAO].capitulos[8].versos[49] = wxT("Jesus respondeu: Eu não tenho demônio; antes honro a meu Pai, e vós me desonrais.");
    b->dados[JOAO].capitulos[8].versos[50] = wxT("Eu não busco a minha glória; há quem a busque, e julgue.");
    b->dados[JOAO].capitulos[8].versos[51] = wxT("Em verdade, em verdade vos digo que, se alguém guardar a minha palavra, nunca verá a morte.");
    b->dados[JOAO].capitulos[8].versos[52] = wxT("Disseram-lhe os judeus: Agora sabemos que tens demônios. Abraão morreu, e também os profetas; e tu dizes: Se alguém guardar a minha palavra, nunca provará a morte!");
    b->dados[JOAO].capitulos[8].versos[53] = wxT("Porventura és tu maior do que nosso pai Abraão, que morreu? Também os profetas morreram; quem pretendes tu ser?");
    b->dados[JOAO].capitulos[8].versos[54] = wxT("Respondeu Jesus: Se eu me glorificar a mim mesmo, a minha glória não é nada; quem me glorifica é meu Pai, do qual vós dizeis que é o vosso Deus;");
    b->dados[JOAO].capitulos[8].versos[55] = wxT("e vós não o conheceis; mas eu o conheço; e se disser que não o conheço, serei mentiroso como vós; mas eu o conheço, e guardo a sua palavra.");
    b->dados[JOAO].capitulos[8].versos[56] = wxT("Abraão, vosso pai, exultou por ver o meu dia; viu-o, e alegrou-se.");
    b->dados[JOAO].capitulos[8].versos[57] = wxT("Disseram-lhe, pois, os judeus: Ainda não tens cinqüenta anos, e viste Abraão?");
    b->dados[JOAO].capitulos[8].versos[58] = wxT("Respondeu-lhes Jesus: Em verdade, em verdade vos digo que antes que Abraão existisse, eu sou.");
    b->dados[JOAO].capitulos[8].versos[59] = wxT("Então pegaram em pedras para lhe atirarem; mas Jesus ocultou-se, e saiu do templo.");

    b->dados[JOAO].capitulos[9].versos[1] = wxT("E passando Jesus, viu um homem cego de nascença.");
    b->dados[JOAO].capitulos[9].versos[2] = wxT("Perguntaram-lhe os seus discípulos: Rabi, quem pecou, este ou seus pais, para que nascesse cego?");
    b->dados[JOAO].capitulos[9].versos[3] = wxT("Respondeu Jesus: Nem ele pecou nem seus pais; mas foi para que nele se manifestem as obras de Deus.");
    b->dados[JOAO].capitulos[9].versos[4] = wxT("Importa que façamos as obras daquele que me enviou, enquanto é dia; vem a noite, quando ninguém pode trabalhar.");
    b->dados[JOAO].capitulos[9].versos[5] = wxT("Enquanto estou no mundo, sou a luz do mundo.");
    b->dados[JOAO].capitulos[9].versos[6] = wxT("Dito isto, cuspiu no chão e com a saliva fez lodo, e untou com lodo os olhos do cego,");
    b->dados[JOAO].capitulos[9].versos[7] = wxT("e disse-lhe: Vai, lava-te no tanque de Siloé {que significa Enviado}. E ele foi, lavou-se, e voltou vendo.");
    b->dados[JOAO].capitulos[9].versos[8] = wxT("Então os vizinhos e aqueles que antes o tinham visto, quando mendigo, perguntavam: Não é este o mesmo que se sentava a mendigar?");
    b->dados[JOAO].capitulos[9].versos[9] = wxT("Uns diziam: É ele. E outros: Não é, mas se parece com ele. Ele dizia: Sou eu.");
    b->dados[JOAO].capitulos[9].versos[10] = wxT("Perguntaram-lhe, pois: Como se te abriram os olhos?");
    b->dados[JOAO].capitulos[9].versos[11] = wxT("Respondeu ele: O homem que se chama Jesus fez lodo, untou-me os olhos, e disse-me: Vai a Siloé e lava-te. Fui, pois, lavei-me, e fiquei vendo.");
    b->dados[JOAO].capitulos[9].versos[12] = wxT("E perguntaram-lhe: Onde está ele? Respondeu: Não sei.");
    b->dados[JOAO].capitulos[9].versos[13] = wxT("Levaram aos fariseus o que fora cego.");
    b->dados[JOAO].capitulos[9].versos[14] = wxT("Ora, era sábado o dia em que Jesus fez o lodo e lhe abriu os olhos.");
    b->dados[JOAO].capitulos[9].versos[15] = wxT("Então os fariseus também se puseram a perguntar-lhe como recebera a vista. Respondeu-lhes ele: Pôs-me lodo sobre os olhos, lavei-me e vejo.");
    b->dados[JOAO].capitulos[9].versos[16] = wxT("Por isso alguns dos fariseus diziam: Este homem não é de Deus; pois não guarda o sábado. Diziam outros: Como pode um homem pecador fazer tais sinais? E havia dissensão entre eles.");
    b->dados[JOAO].capitulos[9].versos[17] = wxT("Tornaram, pois, a perguntar ao cego: Que dizes tu a respeito dele, visto que te abriu os olhos? E ele respondeu: É profeta.");
    b->dados[JOAO].capitulos[9].versos[18] = wxT("Os judeus, porém, não acreditaram que ele tivesse sido cego e recebido a vista, enquanto não chamaram os pais do que fora curado,");
    b->dados[JOAO].capitulos[9].versos[19] = wxT("e lhes perguntaram: É este o vosso filho, que dizeis ter nascido cego? Como, pois, vê agora?");
    b->dados[JOAO].capitulos[9].versos[20] = wxT("Responderam seus pais: Sabemos que este é o nosso filho, e que nasceu cego;");
    b->dados[JOAO].capitulos[9].versos[21] = wxT("mas como agora vê, não sabemos; ou quem lhe abriu os olhos, nós não sabemos; perguntai a ele mesmo; tem idade; ele falará por si mesmo.");
    b->dados[JOAO].capitulos[9].versos[22] = wxT("Isso disseram seus pais, porque temiam os judeus, porquanto já tinham estes combinado que se alguém confessasse ser Jesus o Cristo, fosse expulso da sinagoga.");
    b->dados[JOAO].capitulos[9].versos[23] = wxT("Por isso é que seus pais disseram: Tem idade, perguntai-lho a ele mesmo.");
    b->dados[JOAO].capitulos[9].versos[24] = wxT("Então chamaram pela segunda vez o homem que fora cego, e lhe disseram: Dá glória a Deus; nós sabemos que esse homem é pecador.");
    b->dados[JOAO].capitulos[9].versos[25] = wxT("Respondeu ele: Se é pecador, não sei; uma coisa sei: eu era cego, e agora vejo.");
    b->dados[JOAO].capitulos[9].versos[26] = wxT("Perguntaram-lhe pois: Que foi que te fez? Como te abriu os olhos?");
    b->dados[JOAO].capitulos[9].versos[27] = wxT("Respondeu-lhes: Já vo-lo disse, e não atendestes; para que o quereis tornar a ouvir? Acaso também vós quereis tornar-vos discípulos dele?");
    b->dados[JOAO].capitulos[9].versos[28] = wxT("Então o injuriaram, e disseram: Discípulo dele és tu; nós porém, somos discípulos de Moisés.");
    b->dados[JOAO].capitulos[9].versos[29] = wxT("Sabemos que Deus falou a Moisés; mas quanto a este, não sabemos donde é.");
    b->dados[JOAO].capitulos[9].versos[30] = wxT("Respondeu-lhes o homem: Nisto, pois, está a maravilha: não sabeis donde ele é, e entretanto ele me abriu os olhos;");
    b->dados[JOAO].capitulos[9].versos[31] = wxT("sabemos que Deus não ouve a pecadores; mas, se alguém for temente a Deus, e fizer a sua vontade, a esse ele ouve.");
    b->dados[JOAO].capitulos[9].versos[32] = wxT("Desde o princípio do mundo nunca se ouviu que alguém abrisse os olhos a um cego de nascença.");
    b->dados[JOAO].capitulos[9].versos[33] = wxT("Se este não fosse de Deus, nada poderia fazer.");
    b->dados[JOAO].capitulos[9].versos[34] = wxT("Replicaram-lhe eles: Tu nasceste todo em pecados, e vens nos ensinar a nós? E expulsaram-no.");
    b->dados[JOAO].capitulos[9].versos[35] = wxT("Soube Jesus que o haviam expulsado; e achando-o perguntou-lhe: Crês tu no Filho do homem?");
    b->dados[JOAO].capitulos[9].versos[36] = wxT("Respondeu ele: Quem é, senhor, para que nele creia?");
    b->dados[JOAO].capitulos[9].versos[37] = wxT("Disse-lhe Jesus: Já o viste, e é ele quem fala contigo.");
    b->dados[JOAO].capitulos[9].versos[38] = wxT("Disse o homem: Creio, Senhor! E o adorou.");
    b->dados[JOAO].capitulos[9].versos[39] = wxT("Prosseguiu então Jesus: Eu vim a este mundo para juízo, a fim de que os que não vêem vejam, e os que vêem se tornem cegos.");
    b->dados[JOAO].capitulos[9].versos[40] = wxT("Alguns fariseus que ali estavam com ele, ouvindo isso, perguntaram-lhe: Porventura somos nós também cegos?");
    b->dados[JOAO].capitulos[9].versos[41] = wxT("Respondeu-lhes Jesus: Se fosseis cegos, não teríeis pecado; mas como agora dizeis: Nós vemos, permanece o vosso pecado.");

    b->dados[JOAO].capitulos[10].versos[1] = wxT("Em verdade, em verdade vos digo: quem não entra pela porta no aprisco das ovelhas, mas sobe por outra parte, esse é ladrão e salteador.");
    b->dados[JOAO].capitulos[10].versos[2] = wxT("Mas o que entra pela porta é o pastor das ovelhas.");
    b->dados[JOAO].capitulos[10].versos[3] = wxT("A este o porteiro abre; e as ovelhas ouvem a sua voz; e ele chama pelo nome as suas ovelhas, e as conduz para fora.");
    b->dados[JOAO].capitulos[10].versos[4] = wxT("Depois de conduzir para fora todas as que lhe pertencem, vai adiante delas, e as ovelhas o seguem, porque conhecem a sua voz;");
    b->dados[JOAO].capitulos[10].versos[5] = wxT("mas de modo algum seguirão o estranho, antes fugirão dele, porque não conhecem a voz dos estranhos.");
    b->dados[JOAO].capitulos[10].versos[6] = wxT("Jesus propôs-lhes esta parábola, mas eles não entenderam o que era que lhes dizia.");
    b->dados[JOAO].capitulos[10].versos[7] = wxT("Tornou, pois, Jesus a dizer-lhes: Em verdade, em verdade vos digo: eu sou a porta das ovelhas.");
    b->dados[JOAO].capitulos[10].versos[8] = wxT("Todos quantos vieram antes de mim são ladrões e salteadores; mas as ovelhas não os ouviram.");
    b->dados[JOAO].capitulos[10].versos[9] = wxT("Eu sou a porta; se alguém entrar a casa; o filho fica entrará e sairá, e achará pastagens.");
    b->dados[JOAO].capitulos[10].versos[10] = wxT("O ladrão não vem senão para roubar, matar e destruir; eu vim para que tenham vida e a tenham em abundância.");
    b->dados[JOAO].capitulos[10].versos[11] = wxT("Eu sou o bom pastor; o bom pastor dá a sua vida pelas ovelhas.");
    b->dados[JOAO].capitulos[10].versos[12] = wxT("Mas o que é mercenário, e não pastor, de quem não são as ovelhas, vendo vir o lobo, deixa as ovelhas e foge; e o lobo as arrebata e dispersa.");
    b->dados[JOAO].capitulos[10].versos[13] = wxT("Ora, o mercenário foge porque é mercenário, e não se importa com as ovelhas.");
    b->dados[JOAO].capitulos[10].versos[14] = wxT("Eu sou o bom pastor; conheço as minhas ovelhas, e elas me conhecem,");
    b->dados[JOAO].capitulos[10].versos[15] = wxT("assim como o Pai me conhece e eu conheço o Pai; e dou a minha vida pelas ovelhas.");
    b->dados[JOAO].capitulos[10].versos[16] = wxT("Tenho ainda outras ovelhas que não são deste aprisco; a essas também me importa conduzir, e elas ouvirão a minha voz; e haverá um rebanho e um pastor.");
    b->dados[JOAO].capitulos[10].versos[17] = wxT("Por isto o Pai me ama, porque dou a minha vida para a retomar.");
    b->dados[JOAO].capitulos[10].versos[18] = wxT("Ninguém ma tira de mim, mas eu de mim mesmo a dou; tenho autoridade para a dar, e tenho autoridade para retomá-la. Este mandamento recebi de meu Pai.");
    b->dados[JOAO].capitulos[10].versos[19] = wxT("Por causa dessas palavras, houve outra dissensão entre os judeus.");
    b->dados[JOAO].capitulos[10].versos[20] = wxT("E muitos deles diziam: Tem demônio, e perdeu o juízo; por que o escutais?");
    b->dados[JOAO].capitulos[10].versos[21] = wxT("Diziam outros: Essas palavras não são de quem está endemoninhado; pode porventura um demônio abrir os olhos aos cegos?");
    b->dados[JOAO].capitulos[10].versos[22] = wxT("Celebrava-se então em Jerusalém a festa da dedicação. E era inverno.");
    b->dados[JOAO].capitulos[10].versos[23] = wxT("Andava Jesus passeando no templo, no pórtico de Salomão.");
    b->dados[JOAO].capitulos[10].versos[24] = wxT("Rodearam-no, pois, os judeus e lhe perguntavam: Até quando nos deixarás perplexos? Se tu és o Cristo, dize-no-lo abertamente.");
    b->dados[JOAO].capitulos[10].versos[25] = wxT("Respondeu-lhes Jesus: Já vo-lo disse, e não credes. As obras que eu faço em nome de meu Pai, essas dão testemunho de mim.");
    b->dados[JOAO].capitulos[10].versos[26] = wxT("Mas vós não credes, porque não sois das minhas ovelhas.");
    b->dados[JOAO].capitulos[10].versos[27] = wxT("As minhas ovelhas ouvem a minha voz, e eu as conheço, e elas me seguem;");
    b->dados[JOAO].capitulos[10].versos[28] = wxT("eu lhes dou a vida eterna, e jamais perecerão; e ninguém as arrebatará da minha mão.");
    b->dados[JOAO].capitulos[10].versos[29] = wxT("Meu Pai, que mas deu, é maior do que todos; e ninguém pode arrebatá-las da mão de meu Pai.");
    b->dados[JOAO].capitulos[10].versos[30] = wxT("Eu e o Pai somos um.");
    b->dados[JOAO].capitulos[10].versos[31] = wxT("Os judeus pegaram então outra vez em pedras para o apedrejar.");
    b->dados[JOAO].capitulos[10].versos[32] = wxT("Disse-lhes Jesus: Muitas obras boas da parte de meu Pai vos tenho mostrado; por qual destas obras ides apedrejar-me?");
    b->dados[JOAO].capitulos[10].versos[33] = wxT("Responderam-lhe os judeus: Não é por nenhuma obra boa que vamos apedrejar-te, mas por blasfêmia; e porque, sendo tu homem, te fazes Deus.");
    b->dados[JOAO].capitulos[10].versos[34] = wxT("Tornou-lhes Jesus: Não está escrito na vossa lei: Eu disse: Vós sois deuses?");
    b->dados[JOAO].capitulos[10].versos[35] = wxT("Se a lei chamou deuses àqueles a quem a palavra de Deus foi dirigida {e a Escritura não pode ser anulada},");
    b->dados[JOAO].capitulos[10].versos[36] = wxT("àquele a quem o Pai santificou, e enviou ao mundo, dizeis vós: Blasfemas; porque eu disse: Sou Filho de Deus?");
    b->dados[JOAO].capitulos[10].versos[37] = wxT("Se não faço as obras de meu Pai, não me acrediteis.");
    b->dados[JOAO].capitulos[10].versos[38] = wxT("Mas se as faço, embora não me creiais a mim, crede nas obras; para que entendais e saibais que o Pai está em mim e eu no Pai.");
    b->dados[JOAO].capitulos[10].versos[39] = wxT("Outra vez, pois, procuravam prendê-lo; mas ele lhes escapou das mãos.");
    b->dados[JOAO].capitulos[10].versos[40] = wxT("E retirou-se de novo para além do Jordão, para o lugar onde João batizava no princípio; e ali ficou.");
    b->dados[JOAO].capitulos[10].versos[41] = wxT("Muitos foram ter com ele, e diziam: João, na verdade, não fez sinal algum, mas tudo quanto disse deste homem era verdadeiro.");
    b->dados[JOAO].capitulos[10].versos[42] = wxT("E muitos ali creram nele.");

    b->dados[JOAO].capitulos[11].versos[1] = wxT("Ora, estava enfermo um homem chamado Lázaro, de Betânia, aldeia de Maria e de sua irmã Marta.");
    b->dados[JOAO].capitulos[11].versos[2] = wxT("E Maria, cujo irmão Lázaro se achava enfermo, era a mesma que ungiu o Senhor com bálsamo, e lhe enxugou os pés com os seus cabelos.");
    b->dados[JOAO].capitulos[11].versos[3] = wxT("Mandaram, pois, as irmãs dizer a Jesus: Senhor, eis que está enfermo aquele que tu amas.");
    b->dados[JOAO].capitulos[11].versos[4] = wxT("Jesus, porém, ao ouvir isto, disse: Esta enfermidade não é para a morte, mas para glória de Deus, para que o Filho de Deus seja glorificado por ela.");
    b->dados[JOAO].capitulos[11].versos[5] = wxT("Ora, Jesus amava a Marta, e a sua irmã, e a Lázaro.");
    b->dados[JOAO].capitulos[11].versos[6] = wxT("Quando, pois, ouviu que estava enfermo, ficou ainda dois dias no lugar onde se achava.");
    b->dados[JOAO].capitulos[11].versos[7] = wxT("Depois disto, disse a seus discípulos: Vamos outra vez para Judéia.");
    b->dados[JOAO].capitulos[11].versos[8] = wxT("Disseram-lhe eles: Rabi, ainda agora os judeus procuravam apedrejar-te, e voltas para lá?");
    b->dados[JOAO].capitulos[11].versos[9] = wxT("Respondeu Jesus: Não são doze as horas do dia? Se alguém andar de dia, não tropeça, porque vê a luz deste mundo;");
    b->dados[JOAO].capitulos[11].versos[10] = wxT("mas se andar de noite, tropeça, porque nele não há luz.");
    b->dados[JOAO].capitulos[11].versos[11] = wxT("E, tendo assim falado, acrescentou: Lázaro, o nosso amigo, dorme, mas vou despertá-lo do sono.");
    b->dados[JOAO].capitulos[11].versos[12] = wxT("Disseram-lhe, pois, os discípulos: Senhor, se dorme, ficará bom.");
    b->dados[JOAO].capitulos[11].versos[13] = wxT("Mas Jesus falara da sua morte; eles, porém, entenderam que falava do repouso do sono.");
    b->dados[JOAO].capitulos[11].versos[14] = wxT("Então Jesus lhes disse claramente: Lázaro morreu;");
    b->dados[JOAO].capitulos[11].versos[15] = wxT("e, por vossa causa, folgo de que eu lá não estivesse, para que creiais; mas vamos ter com ele.");
    b->dados[JOAO].capitulos[11].versos[16] = wxT("Disse, pois, Tomé, chamado Dídimo, aos seus condiscípulos: Vamos nós também, para morrermos com ele.");
    b->dados[JOAO].capitulos[11].versos[17] = wxT("Chegando pois Jesus, encontrou-o já com quatro dias de sepultura.");
    b->dados[JOAO].capitulos[11].versos[18] = wxT("Ora, Betânia distava de Jerusalém cerca de quinze estádios.");
    b->dados[JOAO].capitulos[11].versos[19] = wxT("E muitos dos judeus tinham vindo visitar Marta e Maria, para as consolar acerca de seu irmão.");
    b->dados[JOAO].capitulos[11].versos[20] = wxT("Marta, pois, ao saber que Jesus chegava, saiu-lhe ao encontro; Maria, porém, ficou sentada em casa.");
    b->dados[JOAO].capitulos[11].versos[21] = wxT("Disse, pois, Marta a Jesus: Senhor, se meu irmão não teria morrido.");
    b->dados[JOAO].capitulos[11].versos[22] = wxT("E mesmo agora sei que tudo quanto pedires a Deus, Deus to concederá.");
    b->dados[JOAO].capitulos[11].versos[23] = wxT("Respondeu-lhe Jesus: Teu irmão há de ressurgir.");
    b->dados[JOAO].capitulos[11].versos[24] = wxT("Disse-lhe Marta: Sei que ele há de ressurgir na ressurreição, no último dia.");
    b->dados[JOAO].capitulos[11].versos[25] = wxT("Declarou-lhe Jesus: Eu sou a ressurreição e a vida; quem crê em mim, ainda que morra, viverá;");
    b->dados[JOAO].capitulos[11].versos[26] = wxT("e todo aquele que vive, e crê em mim, jamais morrerá. Crês isto?");
    b->dados[JOAO].capitulos[11].versos[27] = wxT("Respondeu-lhe Marta: Sim, Senhor, eu creio que tu és o Cristo, o Filho de Deus, que havia de vir ao mundo.");
    b->dados[JOAO].capitulos[11].versos[28] = wxT("Dito isto, retirou-se e foi chamar em segredo a Maria, sua irmã, e lhe disse: O Mestre está aí, e te chama.");
    b->dados[JOAO].capitulos[11].versos[29] = wxT("Ela, ouvindo isto, levantou-se depressa, e foi ter com ele.");
    b->dados[JOAO].capitulos[11].versos[30] = wxT("Pois Jesus ainda não havia entrado na aldeia, mas estava no lugar onde Marta o encontrara.");
    b->dados[JOAO].capitulos[11].versos[31] = wxT("Então os judeus que estavam com Maria em casa e a consolavam, vendo-a levantar-se apressadamente e sair, seguiram-na, pensando que ia ao sepulcro para chorar ali.");
    b->dados[JOAO].capitulos[11].versos[32] = wxT("Tendo, pois, Maria chegado ao lugar onde Jesus estava, e vendo-a, lançou-se-lhe aos pés e disse: Senhor, se tu estiveras aqui, meu irmão não teria morrido.");
    b->dados[JOAO].capitulos[11].versos[33] = wxT("Jesus, pois, quando a viu chorar, e chorarem também os judeus que com ela vinham, comoveu-se em espírito, e perturbou-se,");
    b->dados[JOAO].capitulos[11].versos[34] = wxT("e perguntou: Onde o puseste? Responderam-lhe: Senhor, vem e vê.");
    b->dados[JOAO].capitulos[11].versos[35] = wxT("Jesus chorou.");
    b->dados[JOAO].capitulos[11].versos[36] = wxT("Disseram então os judeus: Vede como o amava.");
    b->dados[JOAO].capitulos[11].versos[37] = wxT("Mas alguns deles disseram: Não podia ele, que abriu os olhos ao cego, fazer também que este não morreste?");
    b->dados[JOAO].capitulos[11].versos[38] = wxT("Jesus, pois, comovendo-se outra vez, profundamente, foi ao sepulcro; era uma gruta, e tinha uma pedra posta sobre ela.");
    b->dados[JOAO].capitulos[11].versos[39] = wxT("Disse Jesus: Tirai a pedra. Marta, irmã do defunto, disse-lhe: Senhor, já cheira mal, porque está morto há quase quatro dias.");
    b->dados[JOAO].capitulos[11].versos[40] = wxT("Respondeu-lhe Jesus: Não te disse que, se creres, verás a glória de Deus?");
    b->dados[JOAO].capitulos[11].versos[41] = wxT("Tiraram então a pedra. E Jesus, levantando os olhos ao céu, disse: Pai, graças te dou, porque me ouviste.");
    b->dados[JOAO].capitulos[11].versos[42] = wxT("Eu sabia que sempre me ouves; mas por causa da multidão que está em redor é que assim falei, para que eles creiam que tu me enviaste.");
    b->dados[JOAO].capitulos[11].versos[43] = wxT("E, tendo dito isso, clamou em alta voz: Lázaro, vem para fora!");
    b->dados[JOAO].capitulos[11].versos[44] = wxT("Saiu o que estivera morto, ligados os pés e as mãos com faixas, e o seu rosto envolto num lenço. Disse-lhes Jesus: Desligai-o e deixai-o ir.");
    b->dados[JOAO].capitulos[11].versos[45] = wxT("Muitos, pois, dentre os judeus que tinham vindo visitar Maria, e que tinham visto o que Jesus fizera, creram nele.");
    b->dados[JOAO].capitulos[11].versos[46] = wxT("Mas alguns deles foram ter com os fariseus e disseram-lhes o que Jesus tinha feito.");
    b->dados[JOAO].capitulos[11].versos[47] = wxT("Então os principais sacerdotes e os fariseus reuniram o sinédrio e diziam: Que faremos? porquanto este homem vem operando muitos sinais.");
    b->dados[JOAO].capitulos[11].versos[48] = wxT("Se o deixarmos assim, todos crerão nele, e virão os romanos, e nos tirarão tanto o nosso lugar como a nossa nação.");
    b->dados[JOAO].capitulos[11].versos[49] = wxT("Um deles, porém, chamado Caifás, que era sumo sacerdote naquele ano, disse-lhes: Vós nada sabeis,");
    b->dados[JOAO].capitulos[11].versos[50] = wxT("nem considerais que vos convém que morra um só homem pelo povo, e que não pereça a nação toda.");
    b->dados[JOAO].capitulos[11].versos[51] = wxT("Ora, isso não disse ele por si mesmo; mas, sendo o sumo sacerdote naquele ano, profetizou que Jesus havia de morrer pela nação,");
    b->dados[JOAO].capitulos[11].versos[52] = wxT("e não somente pela nação, mas também para congregar num só corpo os filhos de Deus que estão dispersos.");
    b->dados[JOAO].capitulos[11].versos[53] = wxT("Desde aquele dia, pois, tomavam conselho para o matarem.");
    b->dados[JOAO].capitulos[11].versos[54] = wxT("De sorte que Jesus já não andava manifestamente entre os judeus, mas retirou-se dali para a região vizinha ao deserto, a uma cidade chamada Efraim; e ali demorou com os seus discípulos.");
    b->dados[JOAO].capitulos[11].versos[55] = wxT("Ora, estava próxima a páscoa dos judeus, e dessa região subiram muitos a Jerusalém, antes da páscoa, para se purificarem.");
    b->dados[JOAO].capitulos[11].versos[56] = wxT("Buscavam, pois, a Jesus e diziam uns aos outros, estando no templo: Que vos parece? Não virá ele à festa?");
    b->dados[JOAO].capitulos[11].versos[57] = wxT("Ora, os principais sacerdotes e os fariseus tinham dado ordem que, se alguém soubesse onde ele estava, o denunciasse, para que o prendessem.");

    b->dados[JOAO].capitulos[12].versos[1] = wxT("Veio, pois, Jesus seis dias antes da páscoa, a Betânia, onde estava Lázaro, a quem ele ressuscitara dentre os mortos.");
    b->dados[JOAO].capitulos[12].versos[2] = wxT("Deram-lhe ali uma ceia; Marta servia, e Lázaro era um dos que estavam à mesa com ele.");
    b->dados[JOAO].capitulos[12].versos[3] = wxT("Então Maria, tomando uma libra de bálsamo de nardo puro, de grande preço, ungiu os pés de Jesus, e os enxugou com os seus cabelos; e encheu-se a casa do cheiro do bálsamo.");
    b->dados[JOAO].capitulos[12].versos[4] = wxT("Mas Judas Iscariotes, um dos seus discípulos, aquele que o havia de trair disse:");
    b->dados[JOAO].capitulos[12].versos[5] = wxT("Por que não se vendeu este bálsamo por trezentos denários e não se deu aos pobres?");
    b->dados[JOAO].capitulos[12].versos[6] = wxT("Ora, ele disse isto, não porque tivesse cuidado dos pobres, mas porque era ladrão e, tendo a bolsa, subtraía o que nela se lançava.");
    b->dados[JOAO].capitulos[12].versos[7] = wxT("Respondeu, pois Jesus: Deixa-a; para o dia da minha preparação para a sepultura o guardou;");
    b->dados[JOAO].capitulos[12].versos[8] = wxT("porque os pobres sempre os tendes convosco; mas a mim nem sempre me tendes.");
    b->dados[JOAO].capitulos[12].versos[9] = wxT("E grande número dos judeus chegou a saber que ele estava ali: e afluiram, não só por causa de Jesus mas também para verem a Lázaro, a quem ele ressuscitara dentre os mortos.");
    b->dados[JOAO].capitulos[12].versos[10] = wxT("Mas os principais sacerdotes deliberaram matar também a Lázaro;");
    b->dados[JOAO].capitulos[12].versos[11] = wxT("porque muitos, por causa dele, deixavam os judeus e criam em Jesus.");
    b->dados[JOAO].capitulos[12].versos[12] = wxT("No dia seguinte, as grandes multidões que tinham vindo à festa, ouvindo dizer que Jesus vinha a Jerusalém,");
    b->dados[JOAO].capitulos[12].versos[13] = wxT("tomaram ramos de palmeiras, e saíram-lhe ao encontro, e clamavam: Hosana! Bendito o que vem em nome do Senhor! Bendito o rei de Israel!");
    b->dados[JOAO].capitulos[12].versos[14] = wxT("E achou Jesus um jumentinho e montou nele, conforme está escrito:");
    b->dados[JOAO].capitulos[12].versos[15] = wxT("Não temas, ó filha de Sião; eis que vem teu Rei, montado sobre o filho de uma jumenta.");
    b->dados[JOAO].capitulos[12].versos[16] = wxT("Os seus discípulos, porém, a princípio não entenderam isto; mas quando Jesus foi glorificado, então eles se lembraram de que estas coisas estavam escritas a respeito dele, e de que assim lhe fizeram.");
    b->dados[JOAO].capitulos[12].versos[17] = wxT("Dava-lhe, pois, testemunho a multidão que estava com ele quando chamara a Lázaro da sepultura e o ressuscitara dentre os mortos;");
    b->dados[JOAO].capitulos[12].versos[18] = wxT("e foi por isso que a multidão lhe saiu ao encontro, por ter ouvido que ele fizera este sinal.");
    b->dados[JOAO].capitulos[12].versos[19] = wxT("De sorte que os fariseus disseram entre si: Vedes que nada aproveitais? eis que o mundo inteiro vai após ele.");
    b->dados[JOAO].capitulos[12].versos[20] = wxT("Ora, entre os que tinham subido a adorar na festa havia alguns gregos.");
    b->dados[JOAO].capitulos[12].versos[21] = wxT("Estes, pois, dirigiram-se a Felipe, que era de Betsaida da Galiléia, e rogaram-lhe, dizendo: Senhor, queríamos ver a Jesus.");
    b->dados[JOAO].capitulos[12].versos[22] = wxT("Felipe foi dizê-lo a André, e então André e Felipe foram dizê-lo a Jesus.");
    b->dados[JOAO].capitulos[12].versos[23] = wxT("Respondeu-lhes Jesus: É chegada a hora de ser glorificado o Filho do homem.");
    b->dados[JOAO].capitulos[12].versos[24] = wxT("Em verdade, em verdade vos digo: Se o grão de trigo caindo na terra não morrer, fica ele só; mas se morrer, dá muito fruto.");
    b->dados[JOAO].capitulos[12].versos[25] = wxT("Quem ama a sua vida, perdê-la-á; e quem neste mundo odeia a sua vida, guardá-la-á para a vida eterna.");
    b->dados[JOAO].capitulos[12].versos[26] = wxT("Se alguém me quiser servir, siga-me; e onde eu estiver, ali estará também o meu servo; se alguém me servir, o Pai o honrará.");
    b->dados[JOAO].capitulos[12].versos[27] = wxT("Agora a minha alma está perturbada; e que direi eu? Pai, salva-me desta hora? Mas para isto vim a esta hora.");
    b->dados[JOAO].capitulos[12].versos[28] = wxT("Pai, glorifica o teu nome. Veio, então, do céu esta voz: Já o tenho glorificado, e outra vez o glorificarei.");
    b->dados[JOAO].capitulos[12].versos[29] = wxT("A multidão, pois, que ali estava, e que a ouvira, dizia ter havido um trovão; outros diziam: Um anjo lhe falou.");
    b->dados[JOAO].capitulos[12].versos[30] = wxT("Respondeu Jesus: Não veio esta voz por minha causa, mas por causa de vós.");
    b->dados[JOAO].capitulos[12].versos[31] = wxT("Agora é o juízo deste mundo; agora será expulso o príncipe deste mundo.");
    b->dados[JOAO].capitulos[12].versos[32] = wxT("E eu, quando for levantado da terra, todos atrairei a mim.");
    b->dados[JOAO].capitulos[12].versos[33] = wxT("Isto dizia, significando de que modo havia de morrer.");
    b->dados[JOAO].capitulos[12].versos[34] = wxT("Respondeu-lhe a multidão: Nós temos ouvido da lei que o Cristo permanece para sempre; e como dizes tu: Importa que o Filho do homem seja levantado? Quem é esse Filho do homem?");
    b->dados[JOAO].capitulos[12].versos[35] = wxT("Disse-lhes então Jesus: Ainda por um pouco de tempo a luz está entre vós. Andai enquanto tendes a luz, para que as trevas não vos apanhem; pois quem anda nas trevas não sabe para onde vai.");
    b->dados[JOAO].capitulos[12].versos[36] = wxT("Enquanto tendes a luz, crede na luz, para que vos torneis filhos da luz. Havendo Jesus assim falado, retirou-se e escondeu-se deles.");
    b->dados[JOAO].capitulos[12].versos[37] = wxT("E embora tivesse operado tantos sinais diante deles, não criam nele;");
    b->dados[JOAO].capitulos[12].versos[38] = wxT("para que se cumprisse a palavra do profeta Isaías: Senhor, quem creu em nossa pregação? e aquem foi revelado o braço do Senhor?");
    b->dados[JOAO].capitulos[12].versos[39] = wxT("Por isso não podiam crer, porque, como disse ainda Isaías:");
    b->dados[JOAO].capitulos[12].versos[40] = wxT("Cegou-lhes os olhos e endureceu-lhes o coração, para que não vejam com os olhos e entendam com o coração, e se convertam, e eu os cure.");
    b->dados[JOAO].capitulos[12].versos[41] = wxT("Estas coisas disse Isaías, porque viu a sua glória, e dele falou.");
    b->dados[JOAO].capitulos[12].versos[42] = wxT("Contudo, muitos dentre as próprias autoridades creram nele; mas por causa dos fariseus não o confessavam, para não serem expulsos da sinagoga;");
    b->dados[JOAO].capitulos[12].versos[43] = wxT("porque amaram mais a glória dos homens do que a glória de Deus.");
    b->dados[JOAO].capitulos[12].versos[44] = wxT("Clamou Jesus, dizendo: Quem crê em mim, crê, não em mim, mas naquele que me enviou.");
    b->dados[JOAO].capitulos[12].versos[45] = wxT("E quem me vê a mim, vê aquele que me enviou.");
    b->dados[JOAO].capitulos[12].versos[46] = wxT("Eu, que sou a luz, vim ao mundo, para que todo aquele que crê em mim não permaneça nas trevas.");
    b->dados[JOAO].capitulos[12].versos[47] = wxT("E, se alguém ouvir as minhas palavras, e não as guardar, eu não o julgo; pois eu vim, não para julgar o mundo, mas para salvar o mundo.");
    b->dados[JOAO].capitulos[12].versos[48] = wxT("Quem me rejeita, e não recebe as minhas palavras, já tem quem o julgue; a palavra que tenho pregado, essa o julgará no último dia.");
    b->dados[JOAO].capitulos[12].versos[49] = wxT("Porque eu não falei por mim mesmo; mas o Pai, que me enviou, esse me deu mandamento quanto ao que dizer e como falar.");
    b->dados[JOAO].capitulos[12].versos[50] = wxT("E sei que o seu mandamento é vida eterna. Aquilo, pois, que eu falo, falo-o exatamente como o Pai me ordenou.");

    b->dados[JOAO].capitulos[13].versos[1] = wxT("Antes da festa da páscoa, sabendo Jesus que era chegada a sua hora de passar deste mundo para o Pai, e havendo amado os seus que estavam no mundo, amou-os até o fim.");
    b->dados[JOAO].capitulos[13].versos[2] = wxT("Enquanto ceavam, tendo já o Diabo posto no coração de Judas, filho de Simão Iscariotes, que o traísse,");
    b->dados[JOAO].capitulos[13].versos[3] = wxT("Jesus, sabendo que o Pai lhe entregara tudo nas mãos, e que viera de Deus e para Deus voltava,");
    b->dados[JOAO].capitulos[13].versos[4] = wxT("levantou-se da ceia, tirou o manto e, tomando uma toalha, cingiu-se.");
    b->dados[JOAO].capitulos[13].versos[5] = wxT("Depois deitou água na bacia e começou a lavar os pés aos discípulos, e a enxugar-lhos com a toalha com que estava cingido.");
    b->dados[JOAO].capitulos[13].versos[6] = wxT("Chegou, pois, a Simão Pedro, que lhe disse: Senhor, lavas-me os pés a mim?");
    b->dados[JOAO].capitulos[13].versos[7] = wxT("Respondeu-lhe Jesus: O que eu faço, tu não o sabes agora; mas depois o entenderás.");
    b->dados[JOAO].capitulos[13].versos[8] = wxT("Tornou-lhe Pedro: Nunca me lavarás os pés. Replicou-lhe Jesus: Se eu não te lavar, não tens parte comigo.");
    b->dados[JOAO].capitulos[13].versos[9] = wxT("Disse-lhe Simão Pedro: Senhor, não somente os meus pés, mas também as mãos e a cabeça.");
    b->dados[JOAO].capitulos[13].versos[10] = wxT("Respondeu-lhe Jesus: Aquele que se banhou não necessita de lavar senão os pés, pois no mais está todo limpo; e vós estais limpos, mas não todos.");
    b->dados[JOAO].capitulos[13].versos[11] = wxT("Pois ele sabia quem o estava traindo; por isso disse: Nem todos estais limpos.");
    b->dados[JOAO].capitulos[13].versos[12] = wxT("Ora, depois de lhes ter lavado os pés, tomou o manto, tornou a reclinar-se à mesa e perguntou-lhes: Entendeis o que vos tenho feito?");
    b->dados[JOAO].capitulos[13].versos[13] = wxT("Vós me chamais Mestre e Senhor; e dizeis bem, porque eu o sou.");
    b->dados[JOAO].capitulos[13].versos[14] = wxT("Ora, se eu, o Senhor e Mestre, vos lavei os pés, também vós deveis lavar os pés uns aos outros.");
    b->dados[JOAO].capitulos[13].versos[15] = wxT("Porque eu vos dei exemplo, para que, como eu vos fiz, façais vós também.");
    b->dados[JOAO].capitulos[13].versos[16] = wxT("Em verdade, em verdade vos digo: Não é o servo maior do que o seu senhor, nem o enviado maior do que aquele que o enviou.");
    b->dados[JOAO].capitulos[13].versos[17] = wxT("Se sabeis estas coisas, bem-aventurados sois se as praticardes.");
    b->dados[JOAO].capitulos[13].versos[18] = wxT("Não falo de todos vós; eu conheço aqueles que escolhi; mas para que se cumprisse a escritura: O que comia do meu pão, levantou contra mim o seu calcanhar.");
    b->dados[JOAO].capitulos[13].versos[19] = wxT("Desde já no-lo digo, antes que suceda, para que, quando suceder, creiais que eu sou.");
    b->dados[JOAO].capitulos[13].versos[20] = wxT("Em verdade, em verdade vos digo: Quem receber aquele que eu enviar, a mim me recebe; e quem me recebe a mim, recebe aquele que me enviou.");
    b->dados[JOAO].capitulos[13].versos[21] = wxT("Tendo Jesus dito isto, turbou-se em espírito, e declarou: Em verdade, em verdade vos digo que um de vós me há de trair.");
    b->dados[JOAO].capitulos[13].versos[22] = wxT("Os discípulos se entreolhavam, perplexos, sem saber de quem ele falava.");
    b->dados[JOAO].capitulos[13].versos[23] = wxT("Ora, achava-se reclinado sobre o peito de Jesus um de seus discípulos, aquele a quem Jesus amava.");
    b->dados[JOAO].capitulos[13].versos[24] = wxT("A esse, pois, fez Simão Pedro sinal, e lhe pediu: Pergunta-lhe de quem é que fala.");
    b->dados[JOAO].capitulos[13].versos[25] = wxT("Aquele discípulo, recostando-se assim ao peito de Jesus, perguntou-lhe: Senhor, quem é?");
    b->dados[JOAO].capitulos[13].versos[26] = wxT("Respondeu Jesus: É aquele a quem eu der o pedaço de pão molhado. Tendo, pois, molhado um bocado de pão, deu-o a Judas, filho de Simão Iscariotes.");
    b->dados[JOAO].capitulos[13].versos[27] = wxT("E, logo após o bocado, entrou nele Satanás. Disse-lhe, pois, Jesus: O que fazes, faze-o depressa.");
    b->dados[JOAO].capitulos[13].versos[28] = wxT("E nenhum dos que estavam à mesa percebeu a que propósito lhe disse isto;");
    b->dados[JOAO].capitulos[13].versos[29] = wxT("pois, como Judas tinha a bolsa, pensavam alguns que Jesus lhe queria dizer: Compra o que nos é necessário para a festa; ou, que desse alguma coisa aos pobres.");
    b->dados[JOAO].capitulos[13].versos[30] = wxT("Então ele, tendo recebido o bocado saiu logo. E era noite.");
    b->dados[JOAO].capitulos[13].versos[31] = wxT("Tendo ele, pois, saído, disse Jesus: Agora é glorificado o Filho do homem, e Deus é glorificado nele;");
    b->dados[JOAO].capitulos[13].versos[32] = wxT("se Deus é glorificado nele, também Deus o glorificará em si mesmo, e logo o há de glorificar.");
    b->dados[JOAO].capitulos[13].versos[33] = wxT("Filhinhos, ainda por um pouco estou convosco. Procurar-me-eis; e, como eu disse aos judeus, também a vós o digo agora: Para onde eu vou, não podeis vós ir.");
    b->dados[JOAO].capitulos[13].versos[34] = wxT("Um novo mandamento vos dou: que vos ameis uns aos outros; assim como eu vos amei a vós, que também vós vos ameis uns aos outros.");
    b->dados[JOAO].capitulos[13].versos[35] = wxT("Nisto conhecerão todos que sois meus discípulos, se tiverdes amor uns aos outros.");
    b->dados[JOAO].capitulos[13].versos[36] = wxT("Perguntou-lhe Simão Pedro: Senhor, para onde vais? Respondeu Jesus; Para onde eu vou, não podes agora seguir-me; mais tarde, porém, me seguirás.");
    b->dados[JOAO].capitulos[13].versos[37] = wxT("Disse-lhe Pedro: Por que não posso seguir-te agora? Por ti darei a minha vida.");
    b->dados[JOAO].capitulos[13].versos[38] = wxT("Respondeu Jesus: Darás a tua vida por mim? Em verdade, em verdade te digo: Não cantará o galo até que me tenhas negado três vezes.");

    b->dados[JOAO].capitulos[14].versos[1] = wxT("Não se turbe o vosso coração; credes em Deus, crede também em mim.");
    b->dados[JOAO].capitulos[14].versos[2] = wxT("Na casa de meu Pai há muitas moradas; se não fosse assim, eu vo-lo teria dito; vou preparar-vos lugar.");
    b->dados[JOAO].capitulos[14].versos[3] = wxT("E, se eu for e vos preparar lugar, virei outra vez, e vos tomarei para mim mesmo, para que onde eu estiver estejais vós também.");
    b->dados[JOAO].capitulos[14].versos[4] = wxT("E para onde eu vou vós conheceis o caminho.");
    b->dados[JOAO].capitulos[14].versos[5] = wxT("Disse-lhe Tomé: Senhor, não sabemos para onde vais; e como podemos saber o caminho?");
    b->dados[JOAO].capitulos[14].versos[6] = wxT("Respondeu-lhe Jesus: Eu sou o caminho, e a verdade, e a vida; ninguém vem ao Pai, senão por mim.");
    b->dados[JOAO].capitulos[14].versos[7] = wxT("Se vós me conhecêsseis a mim, também conheceríeis a meu Pai; e já desde agora o conheceis, e o tendes visto.");
    b->dados[JOAO].capitulos[14].versos[8] = wxT("Disse-lhe Felipe: Senhor, mostra-nos o Pai, e isso nos basta.");
    b->dados[JOAO].capitulos[14].versos[9] = wxT("Respondeu-lhe Jesus: Há tanto tempo que estou convosco, e ainda não me conheces, Felipe? Quem me viu a mim, viu o Pai; como dizes tu: Mostra-nos o Pai?");
    b->dados[JOAO].capitulos[14].versos[10] = wxT("Não crês tu que eu estou no Pai, e que o Pai está em mim? As palavras que eu vos digo, não as digo por mim mesmo; mas o Pai, que permanece em mim, é quem faz as suas obras.");
    b->dados[JOAO].capitulos[14].versos[11] = wxT("Crede-me que eu estou no Pai, e que o Pai está em mim; crede ao menos por causa das mesmas obras.");
    b->dados[JOAO].capitulos[14].versos[12] = wxT("Em verdade, em verdade vos digo: Aquele que crê em mim, esse também fará as obras que eu faço, e as fará maiores do que estas; porque eu vou para o Pai;");
    b->dados[JOAO].capitulos[14].versos[13] = wxT("e tudo quanto pedirdes em meu nome, eu o farei, para que o Pai seja glorificado no Filho.");
    b->dados[JOAO].capitulos[14].versos[14] = wxT("Se me pedirdes alguma coisa em meu nome, eu a farei.");
    b->dados[JOAO].capitulos[14].versos[15] = wxT("Se me amardes, guardareis os meus mandamentos.");
    b->dados[JOAO].capitulos[14].versos[16] = wxT("E eu rogarei ao Pai, e ele vos dará outro Ajudador, para que fique convosco para sempre.");
    b->dados[JOAO].capitulos[14].versos[17] = wxT("a saber, o Espírito da verdade, o qual o mundo não pode receber; porque não o vê nem o conhece; mas vós o conheceis, porque ele habita convosco, e estará em vós.");
    b->dados[JOAO].capitulos[14].versos[18] = wxT("Não vos deixarei órfãos; voltarei a vós.");
    b->dados[JOAO].capitulos[14].versos[19] = wxT("Ainda um pouco, e o mundo não me verá mais; mas vós me vereis, porque eu vivo, e vós vivereis.");
    b->dados[JOAO].capitulos[14].versos[20] = wxT("Naquele dia conhecereis que estou em meu Pai, e vós em mim, e eu em vós.");
    b->dados[JOAO].capitulos[14].versos[21] = wxT("Aquele que tem os meus mandamentos e os guarda, esse é o que me ama; e aquele que me ama será amado de meu Pai, e eu o amarei, e me manifestarei a ele.");
    b->dados[JOAO].capitulos[14].versos[22] = wxT("Perguntou-lhe Judas {não o Iscariotes}: O que houve, Senhor, que te hás de manifestar a nós, e não ao mundo?");
    b->dados[JOAO].capitulos[14].versos[23] = wxT("Respondeu-lhe Jesus: Se alguém me amar, guardará a minha palavra; e meu Pai o amará, e viremos a ele, e faremos nele morada.");
    b->dados[JOAO].capitulos[14].versos[24] = wxT("Quem não me ama, não guarda as minhas palavras; ora, a palavra que estais ouvindo não é minha, mas do Pai que me enviou.");
    b->dados[JOAO].capitulos[14].versos[25] = wxT("Estas coisas vos tenho falado, estando ainda convosco.");
    b->dados[JOAO].capitulos[14].versos[26] = wxT("Mas o Ajudador, o Espírito Santo a quem o Pai enviará em meu nome, esse vos ensinará todas as coisas, e vos fará lembrar de tudo quanto eu vos tenho dito.");
    b->dados[JOAO].capitulos[14].versos[27] = wxT("Deixo-vos a paz, a minha paz vos dou; eu não vo-la dou como o mundo a dá. Não se turbe o vosso coração, nem se atemorize.");
    b->dados[JOAO].capitulos[14].versos[28] = wxT("Ouvistes que eu vos disse: Vou, e voltarei a vós. Se me amásseis, alegrar-vos-íeis de que eu vá para o Pai; porque o Pai é maior do que eu.");
    b->dados[JOAO].capitulos[14].versos[29] = wxT("Eu vo-lo disse agora, antes que aconteça, para que, quando acontecer, vós creiais.");
    b->dados[JOAO].capitulos[14].versos[30] = wxT("Já não falarei muito convosco, porque vem o príncipe deste mundo, e ele nada tem em mim;");
    b->dados[JOAO].capitulos[14].versos[31] = wxT("mas, assim como o Pai me ordenou, assim mesmo faço, para que o mundo saiba que eu amo o Pai. Levantai-vos, vamo-nos daqui.");

    b->dados[JOAO].capitulos[15].versos[1] = wxT("Eu sou a videira verdadeira, e meu Pai é o viticultor.");
    b->dados[JOAO].capitulos[15].versos[2] = wxT("Toda vara em mim que não dá fruto, ele a corta; e toda vara que dá fruto, ele a limpa, para que dê mais fruto.");
    b->dados[JOAO].capitulos[15].versos[3] = wxT("Vós já estais limpos pela palavra que vos tenho falado.");
    b->dados[JOAO].capitulos[15].versos[4] = wxT("Permanecei em mim, e eu permanecerei em vós; como a vara de si mesma não pode dar fruto, se não permanecer na videira, assim também vós, se não permanecerdes em mim.");
    b->dados[JOAO].capitulos[15].versos[5] = wxT("Eu sou a videira; vós sois as varas. Quem permanece em mim e eu nele, esse dá muito fruto; porque sem mim nada podeis fazer.");
    b->dados[JOAO].capitulos[15].versos[6] = wxT("Quem não permanece em mim é lançado fora, como a vara, e seca; tais varas são recolhidas, lançadas no fogo e queimadas.");
    b->dados[JOAO].capitulos[15].versos[7] = wxT("Se vós permanecerdes em mim, e as minhas palavras permanecerem em vós, pedi o que quiserdes, e vos será feito.");
    b->dados[JOAO].capitulos[15].versos[8] = wxT("Nisto é glorificado meu Pai, que deis muito fruto; e assim sereis meus discípulos.");
    b->dados[JOAO].capitulos[15].versos[9] = wxT("Como o Pai me amou, assim também eu vos amei; permanecei no meu amor.");
    b->dados[JOAO].capitulos[15].versos[10] = wxT("Se guardardes os meus mandamentos, permanecereis no meu amor; do mesmo modo que eu tenho guardado os mandamentos de meu Pai, e permaneço no seu amor.");
    b->dados[JOAO].capitulos[15].versos[11] = wxT("Estas coisas vos tenho dito, para que o meu gozo permaneça em vós, e o vosso gozo seja completo.");
    b->dados[JOAO].capitulos[15].versos[12] = wxT("O meu mandamento é este: Que vos ameis uns aos outros, assim como eu vos amei.");
    b->dados[JOAO].capitulos[15].versos[13] = wxT("Ninguém tem maior amor do que este, de dar alguém a sua vida pelos seus amigos.");
    b->dados[JOAO].capitulos[15].versos[14] = wxT("Vós sois meus amigos, se fizerdes o que eu vos mando.");
    b->dados[JOAO].capitulos[15].versos[15] = wxT("Já não vos chamo servos, porque o servo não sabe o que faz o seu senhor; mas chamei-vos amigos, porque tudo quanto ouvi de meu Pai vos dei a conhecer.");
    b->dados[JOAO].capitulos[15].versos[16] = wxT("Vós não me escolhestes a mim mas eu vos escolhi a vós, e vos designei, para que vades e deis frutos, e o vosso fruto permaneça, a fim de que tudo quanto pedirdes ao Pai em meu nome, ele vo-lo conceda.");
    b->dados[JOAO].capitulos[15].versos[17] = wxT("Isto vos mando: que vos ameis uns aos outros.");
    b->dados[JOAO].capitulos[15].versos[18] = wxT("Se o mundo vos odeia, sabei que, primeiro do que a vós, me odiou a mim.");
    b->dados[JOAO].capitulos[15].versos[19] = wxT("Se fôsseis do mundo, o mundo amaria o que era seu; mas, porque não sois do mundo, antes eu vos escolhi do mundo, por isso é que o mundo vos odeia.");
    b->dados[JOAO].capitulos[15].versos[20] = wxT("Lembrai-vos da palavra que eu vos disse: Não é o servo maior do que o seu senhor. Se a mim me perseguiram, também vos perseguirão a vós; se guardaram a minha palavra, guardarão também a vossa.");
    b->dados[JOAO].capitulos[15].versos[21] = wxT("Mas tudo isto vos farão por causa do meu nome, porque não conhecem aquele que me enviou.");
    b->dados[JOAO].capitulos[15].versos[22] = wxT("Se eu não viera e não lhes falara, não teriam pecado; agora, porém, não têm desculpa do seu pecado.");
    b->dados[JOAO].capitulos[15].versos[23] = wxT("Aquele que me odeia a mim, odeia também a meu Pai.");
    b->dados[JOAO].capitulos[15].versos[24] = wxT("Se eu entre eles não tivesse feito tais obras, quais nenhum outro fez, não teriam pecado; mas agora, não somente viram, mas também odiaram tanto a mim como a meu Pai.");
    b->dados[JOAO].capitulos[15].versos[25] = wxT("Mas isto é para que se cumpra a palavra que está escrita na sua lei: Odiaram-me sem causa.");
    b->dados[JOAO].capitulos[15].versos[26] = wxT("Quando vier o Ajudador, que eu vos enviarei da parte do Pai, o Espírito da verdade, que do Pai procede, esse dará testemunho de mim;");
    b->dados[JOAO].capitulos[15].versos[27] = wxT("e também vós dareis testemunho, porque estais comigo desde o princípio.");

    b->dados[JOAO].capitulos[16].versos[1] = wxT("Tenho-vos dito estas coisas para que não vos escandalizeis.");
    b->dados[JOAO].capitulos[16].versos[2] = wxT("Expulsar-vos-ão das sinagogas; ainda mais, vem a hora em que qualquer que vos matar julgará prestar um serviço a Deus.");
    b->dados[JOAO].capitulos[16].versos[3] = wxT("E isto vos farão, porque não conheceram ao Pai nem a mim.");
    b->dados[JOAO].capitulos[16].versos[4] = wxT("Mas tenho-vos dito estas coisas, a fim de que, quando chegar aquela hora, vos lembreis de que eu vo-las tinha dito. Não vo-las disse desde o princípio, porque estava convosco.");
    b->dados[JOAO].capitulos[16].versos[5] = wxT("Agora, porém, vou para aquele que me enviou; e nenhum de vós me pergunta: Para onde vais?");
    b->dados[JOAO].capitulos[16].versos[6] = wxT("Antes, porque vos disse isto, o vosso coração se encheu de tristeza.");
    b->dados[JOAO].capitulos[16].versos[7] = wxT("Todavia, digo-vos a verdade, convém-vos que eu vá; pois se eu não for, o Ajudador não virá a vós; mas, se eu for, vo-lo enviarei.");
    b->dados[JOAO].capitulos[16].versos[8] = wxT("E quando ele vier, convencerá o mundo do pecado, da justiça e do juízo:");
    b->dados[JOAO].capitulos[16].versos[9] = wxT("do pecado, porque não crêem em mim;");
    b->dados[JOAO].capitulos[16].versos[10] = wxT("da justiça, porque vou para meu Pai, e não me vereis mais,");
    b->dados[JOAO].capitulos[16].versos[11] = wxT("e do juízo, porque o príncipe deste mundo já está julgado.");
    b->dados[JOAO].capitulos[16].versos[12] = wxT("Ainda tenho muito que vos dizer; mas vós não o podeis suportar agora.");
    b->dados[JOAO].capitulos[16].versos[13] = wxT("Quando vier, porém, aquele, o Espírito da verdade, ele vos guiará a toda a verdade; porque não falará por si mesmo, mas dirá o que tiver ouvido, e vos anunciará as coisas vindouras.");
    b->dados[JOAO].capitulos[16].versos[14] = wxT("Ele me glorificará, porque receberá do que é meu, e vo-lo anunciará.");
    b->dados[JOAO].capitulos[16].versos[15] = wxT("Tudo quanto o Pai tem é meu; por isso eu vos disse que ele, recebendo do que é meu, vo-lo anunciará.");
    b->dados[JOAO].capitulos[16].versos[16] = wxT("Um pouco, e já não me vereis; e outra vez um pouco, e ver-me-eis.");
    b->dados[JOAO].capitulos[16].versos[17] = wxT("Então alguns dos seus discípulos perguntaram uns para os outros: Que é isto que nos diz? Um pouco, e não me vereis; e outra vez um pouco, e ver-me-eis; e: Porquanto vou para o Pai?");
    b->dados[JOAO].capitulos[16].versos[18] = wxT("Diziam pois: Que quer dizer isto: Um pouco? Não compreendemos o que ele está dizendo.");
    b->dados[JOAO].capitulos[16].versos[19] = wxT("Percebeu Jesus que o queriam interrogar, e disse-lhes: Indagais entre vós acerca disto que disse: Um pouco, e não me vereis; e outra vez um pouco, e ver-me-eis?");
    b->dados[JOAO].capitulos[16].versos[20] = wxT("Em verdade, em verdade, vos digo que vós chorareis e vos lamentareis, mas o mundo se alegrará; vós estareis tristes, porém a vossa tristeza se converterá em alegria.");
    b->dados[JOAO].capitulos[16].versos[21] = wxT("A mulher, quando está para dar à luz, sente tristeza porque é chegada a sua hora; mas, depois de ter dado à luz a criança, já não se lembra da aflição, pelo gozo de haver um homem nascido ao mundo.");
    b->dados[JOAO].capitulos[16].versos[22] = wxT("Assim também vós agora, na verdade, tendes tristeza; mas eu vos tornarei a ver, e alegrar-se-á o vosso coração, e a vossa alegria ninguém vo-la tirará.");
    b->dados[JOAO].capitulos[16].versos[23] = wxT("Naquele dia nada me perguntareis. Em verdade, em verdade vos digo que tudo quanto pedirdes ao Pai, ele vo-lo concederá em meu nome.");
    b->dados[JOAO].capitulos[16].versos[24] = wxT("Até agora nada pedistes em meu nome; pedi, e recebereis, para que o vosso gozo seja completo.");
    b->dados[JOAO].capitulos[16].versos[25] = wxT("Disse-vos estas coisas por figuras; chega, porém, a hora em que vos não falarei mais por figuras, mas abertamente vos falarei acerca do Pai.");
    b->dados[JOAO].capitulos[16].versos[26] = wxT("Naquele dia pedireis em meu nome, e não vos digo que eu rogarei por vós ao Pai;");
    b->dados[JOAO].capitulos[16].versos[27] = wxT("pois o Pai mesmo vos ama; visto que vós me amastes e crestes que eu saí de Deus.");
    b->dados[JOAO].capitulos[16].versos[28] = wxT("Saí do Pai, e vim ao mundo; outra vez deixo o mundo, e vou para o Pai.");
    b->dados[JOAO].capitulos[16].versos[29] = wxT("Disseram os seus discípulos: Eis que agora falas abertamente, e não por figura alguma.");
    b->dados[JOAO].capitulos[16].versos[30] = wxT("Agora conhecemos que sabes todas as coisas, e não necessitas de que alguém te interrogue. Por isso cremos que saíste de Deus.");
    b->dados[JOAO].capitulos[16].versos[31] = wxT("Respondeu-lhes Jesus: Credes agora?");
    b->dados[JOAO].capitulos[16].versos[32] = wxT("Eis que vem a hora, e já é chegada, em que vós sereis dispersos cada um para o seu lado, e me deixareis só; mas não estou só, porque o Pai está comigo.");
    b->dados[JOAO].capitulos[16].versos[33] = wxT("Tenho-vos dito estas coisas, para que em mim tenhais paz. No mundo tereis tribulações; mas tende bom ânimo, eu venci o mundo.");

    b->dados[JOAO].capitulos[17].versos[1] = wxT("Depois de assim falar, Jesus, levantando os olhos ao céu, disse: Pai, é chegada a hora; glorifica a teu Filho, para que também o Filho te glorifique;");
    b->dados[JOAO].capitulos[17].versos[2] = wxT("assim como lhe deste autoridade sobre toda a carne, para que dê a vida eterna a todos aqueles que lhe tens dado.");
    b->dados[JOAO].capitulos[17].versos[3] = wxT("E a vida eterna é esta: que te conheçam a ti, como o único Deus verdadeiro, e a Jesus Cristo, aquele que tu enviaste.");
    b->dados[JOAO].capitulos[17].versos[4] = wxT("Eu te glorifiquei na terra, completando a obra que me deste para fazer.");
    b->dados[JOAO].capitulos[17].versos[5] = wxT("Agora, pois, glorifica-me tu, ó Pai, junto de ti mesmo, com aquela glória que eu tinha contigo antes que o mundo existisse.");
    b->dados[JOAO].capitulos[17].versos[6] = wxT("Manifestei o teu nome aos homens que do mundo me deste. Eram teus, e tu mos deste; e guardaram a tua palavra.");
    b->dados[JOAO].capitulos[17].versos[7] = wxT("Agora sabem que tudo quanto me deste provém de ti;");
    b->dados[JOAO].capitulos[17].versos[8] = wxT("porque eu lhes dei as palavras que tu me deste, e eles as receberam, e verdadeiramente conheceram que saí de ti, e creram que tu me enviaste.");
    b->dados[JOAO].capitulos[17].versos[9] = wxT("Eu rogo por eles; não rogo pelo mundo, mas por aqueles que me tens dado, porque são teus;");
    b->dados[JOAO].capitulos[17].versos[10] = wxT("todas as minhas coisas são tuas, e as tuas coisas são minhas; e neles sou glorificado.");
    b->dados[JOAO].capitulos[17].versos[11] = wxT("Eu não estou mais no mundo; mas eles estão no mundo, e eu vou para ti. Pai santo, guarda-os no teu nome, o qual me deste, para que eles sejam um, assim como nós.");
    b->dados[JOAO].capitulos[17].versos[12] = wxT("Enquanto eu estava com eles, eu os guardava no teu nome que me deste; e os conservei, e nenhum deles se perdeu, senão o filho da perdição, para que se cumprisse a Escritura.");
    b->dados[JOAO].capitulos[17].versos[13] = wxT("Mas agora vou para ti; e isto falo no mundo, para que eles tenham a minha alegria completa em si mesmos.");
    b->dados[JOAO].capitulos[17].versos[14] = wxT("Eu lhes dei a tua palavra; e o mundo os odiou, porque não são do mundo, assim como eu não sou do mundo.");
    b->dados[JOAO].capitulos[17].versos[15] = wxT("Não rogo que os tires do mundo, mas que os guardes do Maligno.");
    b->dados[JOAO].capitulos[17].versos[16] = wxT("Eles não são do mundo, assim como eu não sou do mundo.");
    b->dados[JOAO].capitulos[17].versos[17] = wxT("Santifica-os na verdade, a tua palavra é a verdade.");
    b->dados[JOAO].capitulos[17].versos[18] = wxT("Assim como tu me enviaste ao mundo, também eu os enviarei ao mundo.");
    b->dados[JOAO].capitulos[17].versos[19] = wxT("E por eles eu me santifico, para que também eles sejam santificados na verdade.");
    b->dados[JOAO].capitulos[17].versos[20] = wxT("E rogo não somente por estes, mas também por aqueles que pela sua palavra hão de crer em mim;");
    b->dados[JOAO].capitulos[17].versos[21] = wxT("para que todos sejam um; assim como tu, ó Pai, és em mim, e eu em ti, que também eles sejam um em nós; para que o mundo creia que tu me enviaste.");
    b->dados[JOAO].capitulos[17].versos[22] = wxT("E eu lhes dei a glória que a mim me deste, para que sejam um, como nós somos um;");
    b->dados[JOAO].capitulos[17].versos[23] = wxT("eu neles, e tu em mim, para que eles sejam perfeitos em unidade, a fim de que o mundo conheça que tu me enviaste, e que os amaste a eles, assim como me amaste a mim.");
    b->dados[JOAO].capitulos[17].versos[24] = wxT("Pai, desejo que onde eu estou, estejam comigo também aqueles que me tens dado, para verem a minha glória, a qual me deste; pois que me amaste antes da fundação do mundo.");
    b->dados[JOAO].capitulos[17].versos[25] = wxT("Pai justo, o mundo não te conheceu, mas eu te conheço; conheceram que tu me enviaste;");
    b->dados[JOAO].capitulos[17].versos[26] = wxT("e eu lhes fiz conhecer o teu nome, e lho farei conhecer ainda; para que haja neles aquele amor com que me amaste, e também eu neles esteja.");

    b->dados[JOAO].capitulos[18].versos[1] = wxT("Tendo Jesus dito isto, saiu com seus discípulos para o outro lado do ribeiro de Cedrom, onde havia um jardim, e com eles ali entrou.");
    b->dados[JOAO].capitulos[18].versos[2] = wxT("Ora, Judas, que o traía, também conhecia aquele lugar, porque muitas vezes Jesus se reunira ali com os discípulos.");
    b->dados[JOAO].capitulos[18].versos[3] = wxT("Tendo, pois, Judas tomado a corte e uns guardas da parte dos principais sacerdotes e fariseus, chegou ali com lanternas archotes e armas.");
    b->dados[JOAO].capitulos[18].versos[4] = wxT("Sabendo, pois, Jesus tudo o que lhe havia de suceder, adiantou-se e perguntou-lhes: A quem buscais?");
    b->dados[JOAO].capitulos[18].versos[5] = wxT("Responderam-lhe: A Jesus, o nazareno. Disse-lhes Jesus: Sou eu. E Judas, que o traía, também estava com eles.");
    b->dados[JOAO].capitulos[18].versos[6] = wxT("Quando Jesus lhes disse: Sou eu, recuaram, e caíram por terra.");
    b->dados[JOAO].capitulos[18].versos[7] = wxT("Tornou-lhes então a perguntar: A quem buscais? e responderam: A Jesus, o nazareno.");
    b->dados[JOAO].capitulos[18].versos[8] = wxT("Replicou-lhes Jesus: Já vos disse que sou eu; se, pois, é a mim que buscais, deixai ir estes;");
    b->dados[JOAO].capitulos[18].versos[9] = wxT("para que se cumprisse a palavra que dissera: Dos que me tens dado, nenhum deles perdi.");
    b->dados[JOAO].capitulos[18].versos[10] = wxT("Então Simão Pedro, que tinha uma espada, desembainhou-a e feriu o servo do sumo sacerdote, cortando-lhe a orelha direita. O nome do servo era Malco.");
    b->dados[JOAO].capitulos[18].versos[11] = wxT("Disse, pois, Jesus a Pedro: Mete a tua espada na bainha; não hei de beber o cálice que o Pai me deu?");
    b->dados[JOAO].capitulos[18].versos[12] = wxT("Então a escolta, e o comandante, e os guardas dos judeus prenderam a Jesus, e o maniataram.");
    b->dados[JOAO].capitulos[18].versos[13] = wxT("E conduziram-no primeiramente a Anás; pois era sogro de Caifás, sumo sacerdote naquele ano.");
    b->dados[JOAO].capitulos[18].versos[14] = wxT("Ora, Caifás era quem aconselhara aos judeus que convinha morrer um homem pelo povo.");
    b->dados[JOAO].capitulos[18].versos[15] = wxT("Simão Pedro e outro discípulo seguiam a Jesus. Este discípulo era conhecido do sumo sacerdote, e entrou com Jesus no pátio do sumo sacerdote,");
    b->dados[JOAO].capitulos[18].versos[16] = wxT("enquanto Pedro ficava da parte de fora, à porta. Saiu, então, o outro discípulo que era conhecido do sumo sacerdote, falou à porteira, e levou Pedro para dentro.");
    b->dados[JOAO].capitulos[18].versos[17] = wxT("Então a porteira perguntou a Pedro: Não és tu também um dos discípulos deste homem? Respondeu ele: Não sou.");
    b->dados[JOAO].capitulos[18].versos[18] = wxT("Ora, estavam ali os servos e os guardas, que tinham acendido um braseiro e se aquentavam, porque fazia frio; e também Pedro estava ali em pé no meio deles, aquentando-se.");
    b->dados[JOAO].capitulos[18].versos[19] = wxT("Então o sumo sacerdote interrogou Jesus acerca dos seus discípulos e da sua doutrina.");
    b->dados[JOAO].capitulos[18].versos[20] = wxT("Respondeu-lhe Jesus: Eu tenho falado abertamente ao mundo; eu sempre ensinei nas sinagogas e no templo, onde todos os judeus se congregam, e nada falei em oculto.");
    b->dados[JOAO].capitulos[18].versos[21] = wxT("Por que me perguntas a mim? pergunta aos que me ouviram o que é que lhes falei; eis que eles sabem o que eu disse.");
    b->dados[JOAO].capitulos[18].versos[22] = wxT("E, havendo ele dito isso, um dos guardas que ali estavam deu uma bofetada em Jesus, dizendo: É assim que respondes ao sumo sacerdote?");
    b->dados[JOAO].capitulos[18].versos[23] = wxT("Respondeu-lhe Jesus: Se falei mal, dá testemunho do mal; mas, se bem, por que me feres?");
    b->dados[JOAO].capitulos[18].versos[24] = wxT("Então Anás o enviou, maniatado, a Caifás, o sumo sacerdote.");
    b->dados[JOAO].capitulos[18].versos[25] = wxT("E Simão Pedro ainda estava ali, aquentando-se. Perguntaram-lhe, pois: Não és também tu um dos seus discípulos? Ele negou, e disse: Não sou.");
    b->dados[JOAO].capitulos[18].versos[26] = wxT("Um dos servos do sumo sacerdote, parente daquele a quem Pedro cortara a orelha, disse: Não te vi eu no jardim com ele?");
    b->dados[JOAO].capitulos[18].versos[27] = wxT("Pedro negou outra vez, e imediatamente o galo cantou.");
    b->dados[JOAO].capitulos[18].versos[28] = wxT("Depois conduziram Jesus da presença de Caifás para o pretório; era de manhã cedo; e eles não entraram no pretório, para não se contaminarem, mas poderem comer a páscoa.");
    b->dados[JOAO].capitulos[18].versos[29] = wxT("Então Pilatos saiu a ter com eles, e perguntou: Que acusação trazeis contra este homem?");
    b->dados[JOAO].capitulos[18].versos[30] = wxT("Responderam-lhe: Se ele não fosse malfeitor, não to entregaríamos.");
    b->dados[JOAO].capitulos[18].versos[31] = wxT("Disse-lhes, então, Pilatos: Tomai-o vós, e julgai-o segundo a vossa lei. Disseram-lhe os judeus: A nós não nos é lícito tirar a vida a ninguém.");
    b->dados[JOAO].capitulos[18].versos[32] = wxT("Isso foi para que se cumprisse a palavra que dissera Jesus, significando de que morte havia de morrer.");
    b->dados[JOAO].capitulos[18].versos[33] = wxT("Pilatos, pois, tornou a entrar no pretório, chamou a Jesus e perguntou-lhe: És tu o rei dos judeus?");
    b->dados[JOAO].capitulos[18].versos[34] = wxT("Respondeu Jesus: Dizes isso de ti mesmo, ou foram outros que to disseram de mim?");
    b->dados[JOAO].capitulos[18].versos[35] = wxT("Replicou Pilatos: Porventura sou eu judeu? O teu povo e os principais sacerdotes entregaram-te a mim; que fizeste?");
    b->dados[JOAO].capitulos[18].versos[36] = wxT("Respondeu Jesus: O meu reino não é deste mundo; se o meu reino fosse deste mundo, pelejariam os meus servos, para que eu não fosse entregue aos judeus; entretanto o meu reino não é daqui.");
    b->dados[JOAO].capitulos[18].versos[37] = wxT("Perguntou-lhe, pois, Pilatos: Logo tu és rei? Respondeu Jesus: Tu dizes que eu sou rei. Eu para isso nasci, e para isso vim ao mundo, a fim de dar testemunho da verdade. Todo aquele que é da verdade ouve a minha voz.");
    b->dados[JOAO].capitulos[18].versos[38] = wxT("Perguntou-lhe Pilatos: Que é a verdade? E dito isto, de novo saiu a ter com os judeus, e disse-lhes: Não acho nele crime algum.");
    b->dados[JOAO].capitulos[18].versos[39] = wxT("Tendes, porém, por costume que eu vos solte alguém por ocasião da páscoa; quereis, pois, que vos solte o rei dos judeus?");
    b->dados[JOAO].capitulos[18].versos[40] = wxT("Então todos tornaram a clamar dizendo: Este não, mas Barrabás. Ora, Barrabás era salteador.");

    b->dados[JOAO].capitulos[19].versos[1] = wxT("Nisso, pois, Pilatos tomou a Jesus, e mandou açoitá-lo.");
    b->dados[JOAO].capitulos[19].versos[2] = wxT("E os soldados, tecendo uma coroa de espinhos, puseram-lha sobre a cabeça, e lhe vestiram um manto de púrpura;");
    b->dados[JOAO].capitulos[19].versos[3] = wxT("e chegando-se a ele, diziam: Salve, rei dos judeus! e davam-lhe bofetadas.");
    b->dados[JOAO].capitulos[19].versos[4] = wxT("Então Pilatos saiu outra vez, e disse-lhes: Eis aqui vo-lo trago fora, para que saibais que não acho nele crime algum.");
    b->dados[JOAO].capitulos[19].versos[5] = wxT("Saiu, pois, Jesus, trazendo a coroa de espinhos e o manto de púrpura. E disse-lhes Pilatos: Eis o homem!");
    b->dados[JOAO].capitulos[19].versos[6] = wxT("Quando o viram os principais sacerdotes e os guardas, clamaram, dizendo: Crucifica-o! Crucifica-o! Disse-lhes Pilatos: Tomai-o vós, e crucificai-o; porque nenhum crime acho nele.");
    b->dados[JOAO].capitulos[19].versos[7] = wxT("Responderam-lhe os judeus: Nós temos uma lei, e segundo esta lei ele deve morrer, porque se fez Filho de Deus.");
    b->dados[JOAO].capitulos[19].versos[8] = wxT("Ora, Pilatos, quando ouviu esta palavra, mais atemorizado ficou;");
    b->dados[JOAO].capitulos[19].versos[9] = wxT("e entrando outra vez no pretório, perguntou a Jesus: Donde és tu? Mas Jesus não lhe deu resposta.");
    b->dados[JOAO].capitulos[19].versos[10] = wxT("Disse-lhe, então, Pilatos: Não me respondes? não sabes que tenho autoridade para te soltar, e autoridade para te crucificar?");
    b->dados[JOAO].capitulos[19].versos[11] = wxT("Respondeu-lhe Jesus: Nenhuma autoridade terias sobre mim, se de cima não te fora dado; por isso aquele que me entregou a ti, maior pecado tem.");
    b->dados[JOAO].capitulos[19].versos[12] = wxT("Daí em diante Pilatos procurava soltá-lo; mas os judeus clamaram: Se soltares a este, não és amigo de César; todo aquele que se faz rei é contra César.");
    b->dados[JOAO].capitulos[19].versos[13] = wxT("Pilatos, pois, quando ouviu isto, trouxe Jesus para fora e sentou-se no tribunal, no lugar chamado Pavimento, e em hebraico Gabatá.");
    b->dados[JOAO].capitulos[19].versos[14] = wxT("Ora, era a preparação da páscoa, e cerca da hora sexta. E disse aos judeus: Eis o vosso rei.");
    b->dados[JOAO].capitulos[19].versos[15] = wxT("Mas eles clamaram: Tira-o! tira-o! crucifica-o! Disse-lhes Pilatos: Hei de crucificar o vosso rei? responderam, os principais sacerdotes: Não temos rei, senão César.");
    b->dados[JOAO].capitulos[19].versos[16] = wxT("Então lho entregou para ser crucificado.");
    b->dados[JOAO].capitulos[19].versos[17] = wxT("Tomaram, pois, a Jesus; e ele, carregando a sua própria cruz, saiu para o lugar chamado Caveira, que em hebraico se chama Gólgota,");
    b->dados[JOAO].capitulos[19].versos[18] = wxT("onde o crucificaram, e com ele outros dois, um de cada lado, e Jesus no meio.");
    b->dados[JOAO].capitulos[19].versos[19] = wxT("E Pilatos escreveu também um título, e o colocou sobre a cruz; e nele estava escrito: JESUS O NAZARENO, O REI DOS JUDEUS.");
    b->dados[JOAO].capitulos[19].versos[20] = wxT("Muitos dos judeus, pois, leram este título; porque o lugar onde Jesus foi crucificado era próximo da cidade; e estava escrito em hebraico, latim e grego.");
    b->dados[JOAO].capitulos[19].versos[21] = wxT("Diziam então a Pilatos os principais sacerdotes dos judeus: Não escrevas: O rei dos judeus; mas que ele disse: Sou rei dos judeus.");
    b->dados[JOAO].capitulos[19].versos[22] = wxT("Respondeu Pilatos: O que escrevi, escrevi.");
    b->dados[JOAO].capitulos[19].versos[23] = wxT("Tendo, pois, os soldados crucificado a Jesus, tomaram as suas vestes, e fizeram delas quatro partes, para cada soldado uma parte. Tomaram também a túnica; ora a túnica não tinha costura, sendo toda tecida de alto a baixo.");
    b->dados[JOAO].capitulos[19].versos[24] = wxT("Pelo que disseram uns aos outros: Não a rasguemos, mas lancemos sortes sobre ela, para ver de quem será {para que se cumprisse a escritura que diz: Repartiram entre si as minhas vestes, e lançaram sortes}. E, de fato, os soldados assim fizeram.");
    b->dados[JOAO].capitulos[19].versos[25] = wxT("Estavam em pé, junto à cruz de Jesus, sua mãe, e a irmã de sua mãe, e Maria, mulher de Clôpas, e Maria Madalena.");
    b->dados[JOAO].capitulos[19].versos[26] = wxT("Ora, Jesus, vendo ali sua mãe, e ao lado dela o discípulo a quem ele amava, disse a sua mãe: Mulher, eis aí o teu filho.");
    b->dados[JOAO].capitulos[19].versos[27] = wxT("Então disse ao discípulo: Eis aí tua mãe. E desde aquela hora o discípulo a recebeu em sua casa.");
    b->dados[JOAO].capitulos[19].versos[28] = wxT("Depois, sabendo Jesus que todas as coisas já estavam consumadas, para que se cumprisse a Escritura, disse: Tenho sede.");
    b->dados[JOAO].capitulos[19].versos[29] = wxT("Estava ali um vaso cheio de vinagre. Puseram, pois, numa cana de hissopo uma esponja ensopada de vinagre, e lha chegaram à boca.");
    b->dados[JOAO].capitulos[19].versos[30] = wxT("Então Jesus, depois de ter tomado o vinagre, disse: está consumado. E, inclinando a cabeça, entregou o espírito.");
    b->dados[JOAO].capitulos[19].versos[31] = wxT("Ora, os judeus, como era a preparação, e para que no sábado não ficassem os corpos na cruz, pois era grande aquele dia de sábado, rogaram a Pilatos que se lhes quebrassem as pernas, e fossem tirados dali.");
    b->dados[JOAO].capitulos[19].versos[32] = wxT("Foram então os soldados e, na verdade, quebraram as pernas ao primeiro e ao outro que com ele fora crucificado;");
    b->dados[JOAO].capitulos[19].versos[33] = wxT("mas vindo a Jesus, e vendo que já estava morto, não lhe quebraram as pernas;");
    b->dados[JOAO].capitulos[19].versos[34] = wxT("contudo um dos soldados lhe furou o lado com uma lança, e logo saiu sangue e água.");
    b->dados[JOAO].capitulos[19].versos[35] = wxT("E é quem viu isso que dá testemunho, e o seu testemunho é verdadeiro; e sabe que diz a verdade, para que também vós creiais.");
    b->dados[JOAO].capitulos[19].versos[36] = wxT("Porque isto aconteceu para que se cumprisse a escritura: Nenhum dos seus ossos será quebrado.");
    b->dados[JOAO].capitulos[19].versos[37] = wxT("Também há outra escritura que diz: Olharão para aquele que traspassaram.");
    b->dados[JOAO].capitulos[19].versos[38] = wxT("Depois disto, José de Arimatéia, que era discípulo de Jesus, embora oculto por medo dos judeus, rogou a Pilatos que lhe permitisse tirar o corpo de Jesus; e Pilatos lho permitiu. Então foi e o tirou.");
    b->dados[JOAO].capitulos[19].versos[39] = wxT("E Nicodemos, aquele que anteriormente viera ter com Jesus de noite, foi também, levando cerca de cem libras duma mistura de mirra e aloés.");
    b->dados[JOAO].capitulos[19].versos[40] = wxT("Tomaram, pois, o corpo de Jesus, e o envolveram em panos de linho com as especiarias, como os judeus costumavam fazer na preparação para a sepultura.");
    b->dados[JOAO].capitulos[19].versos[41] = wxT("No lugar onde Jesus foi crucificado havia um jardim, e nesse jardim um sepulcro novo, em que ninguém ainda havia sido posto.");
    b->dados[JOAO].capitulos[19].versos[42] = wxT("Ali, pois, por ser a véspera do sábado dos judeus, e por estar perto aquele sepulcro, puseram a Jesus.");

    b->dados[JOAO].capitulos[20].versos[1] = wxT("No primeiro dia da semana Maria Madalena foi ao sepulcro de madrugada, sendo ainda escuro, e viu que a pedra fora removida do sepulcro.");
    b->dados[JOAO].capitulos[20].versos[2] = wxT("Correu, pois, e foi ter com Simão Pedro, e o outro discípulo, a quem Jesus amava, e disse-lhes: Tiraram do sepulcro o Senhor, e não sabemos onde o puseram.");
    b->dados[JOAO].capitulos[20].versos[3] = wxT("Saíram então Pedro e o outro discípulo e foram ao sepulcro.");
    b->dados[JOAO].capitulos[20].versos[4] = wxT("Corriam os dois juntos, mas o outro discípulo correu mais ligeiro do que Pedro, e chegou primeiro ao sepulcro;");
    b->dados[JOAO].capitulos[20].versos[5] = wxT("e, abaixando-se viu os panos de linho ali deixados, todavia não entrou.");
    b->dados[JOAO].capitulos[20].versos[6] = wxT("Chegou, pois, Simão Pedro, que o seguia, e entrou no sepulcro e viu os panos de linho ali deixados,");
    b->dados[JOAO].capitulos[20].versos[7] = wxT("e que o lenço, que estivera sobre a cabeça de Jesus, não estava com os panos, mas enrolado num lugar à parte.");
    b->dados[JOAO].capitulos[20].versos[8] = wxT("Então entrou também o outro discípulo, que chegara primeiro ao sepulcro, e viu e creu.");
    b->dados[JOAO].capitulos[20].versos[9] = wxT("Porque ainda não entendiam a escritura, que era necessário que ele ressurgisse dentre os mortos.");
    b->dados[JOAO].capitulos[20].versos[10] = wxT("Tornaram, pois, os discípulos para casa.");
    b->dados[JOAO].capitulos[20].versos[11] = wxT("Maria, porém, estava em pé, diante do sepulcro, a chorar. Enquanto chorava, abaixou-se a olhar para dentro do sepulcro,");
    b->dados[JOAO].capitulos[20].versos[12] = wxT("e viu dois anjos vestidos de branco sentados onde jazera o corpo de Jesus, um à cabeceira e outro aos pés.");
    b->dados[JOAO].capitulos[20].versos[13] = wxT("E perguntaram-lhe eles: Mulher, por que choras? Respondeu-lhes: Porque tiraram o meu Senhor, e não sei onde o puseram.");
    b->dados[JOAO].capitulos[20].versos[14] = wxT("Ao dizer isso, voltou-se para trás, e viu a Jesus ali em pé, mas não sabia que era Jesus.");
    b->dados[JOAO].capitulos[20].versos[15] = wxT("Perguntou-lhe Jesus: Mulher, por que choras? A quem procuras? Ela, julgando que fosse o jardineiro, respondeu-lhe: Senhor, se tu o levaste, dize-me onde o puseste, e eu o levarei.");
    b->dados[JOAO].capitulos[20].versos[16] = wxT("Disse-lhe Jesus: Maria! Ela, virando-se, disse-lhe em hebraico: Raboni!-que quer dizer, Mestre.");
    b->dados[JOAO].capitulos[20].versos[17] = wxT("Disse-lhe Jesus: Deixa de me tocar, porque ainda não subi ao Pai; mas vai a meus irmãos e dize-lhes que eu subo para meu Pai e vosso Pai, meu Deus e vosso Deus.");
    b->dados[JOAO].capitulos[20].versos[18] = wxT("E foi Maria Madalena anunciar aos discípulos: Vi o Senhor!-e que ele lhe dissera estas coisas.");
    b->dados[JOAO].capitulos[20].versos[19] = wxT("Chegada, pois, a tarde, naquele dia, o primeiro da semana, e estando os discípulos reunidos com as portas cerradas por medo dos judeus, chegou Jesus, pôs-se no meio e disse-lhes: Paz seja convosco.");
    b->dados[JOAO].capitulos[20].versos[20] = wxT("Dito isto, mostrou-lhes as mãos e o lado. Alegraram-se, pois, os discípulos ao verem o Senhor.");
    b->dados[JOAO].capitulos[20].versos[21] = wxT("Disse-lhes, então, Jesus segunda vez: Paz seja convosco; assim como o Pai me enviou, também eu vos envio a vós.");
    b->dados[JOAO].capitulos[20].versos[22] = wxT("E havendo dito isso, assoprou sobre eles, e disse-lhes: Recebei o Espírito Santo.");
    b->dados[JOAO].capitulos[20].versos[23] = wxT("Àqueles a quem perdoardes os pecados, são-lhes perdoados; e àqueles a quem os retiverdes, são-lhes retidos.");
    b->dados[JOAO].capitulos[20].versos[24] = wxT("Ora, Tomé, um dos doze, chamado Dídimo, não estava com eles quando veio Jesus.");
    b->dados[JOAO].capitulos[20].versos[25] = wxT("Diziam-lhe, pois, ou outros discípulos: Vimos o Senhor. Ele, porém, lhes respondeu: Se eu não vir o sinal dos cravos nas mãos, e não meter a mão no seu lado, de maneira nenhuma crerei.");
    b->dados[JOAO].capitulos[20].versos[26] = wxT("Oito dias depois estavam os discípulos outra vez ali reunidos, e Tomé com eles. Chegou Jesus, estando as portas fechadas, pôs-se no meio deles e disse: Paz seja convosco.");
    b->dados[JOAO].capitulos[20].versos[27] = wxT("Depois disse a Tomé: Chega aqui o teu dedo, e vê as minhas mãos; chega a tua mão, e mete-a no meu lado; e não mais sejas incrédulo, mas crente.");
    b->dados[JOAO].capitulos[20].versos[28] = wxT("Respondeu-lhe Tomé: Senhor meu, e Deus meu!");
    b->dados[JOAO].capitulos[20].versos[29] = wxT("Disse-lhe Jesus: Porque me viste, creste? Bem-aventurados os que não viram e creram.");
    b->dados[JOAO].capitulos[20].versos[30] = wxT("Jesus, na verdade, operou na presença de seus discípulos ainda muitos outros sinais que não estão escritos neste livro;");
    b->dados[JOAO].capitulos[20].versos[31] = wxT("estes, porém, estão escritos para que creiais que Jesus é o Cristo, o Filho de Deus, e para que, crendo, tenhais vida em seu nome.");

    b->dados[JOAO].capitulos[21].versos[1] = wxT("Depois disto manifestou-se Jesus outra vez aos discípulos junto do mar de Tiberíades; e manifestou-se deste modo:");
    b->dados[JOAO].capitulos[21].versos[2] = wxT("Estavam juntos Simão Pedro, Tomé, chamado Dídimo, Natanael, que era de Caná da Galiléia, os filhos de Zebedeu, e outros dois dos seus discípulos.");
    b->dados[JOAO].capitulos[21].versos[3] = wxT("Disse-lhes Simão Pedro: Vou pescar. Responderam-lhe: Nós também vamos contigo. Saíram e entraram no barco; e naquela noite nada apanharam.");
    b->dados[JOAO].capitulos[21].versos[4] = wxT("Mas ao romper da manhã, Jesus se apresentou na praia; todavia os discípulos não sabiam que era ele.");
    b->dados[JOAO].capitulos[21].versos[5] = wxT("Disse-lhes, pois, Jesus: Filhos, não tendes nada que comer? Responderam-lhe: Não.");
    b->dados[JOAO].capitulos[21].versos[6] = wxT("Disse-lhes ele: Lançai a rede à direita do barco, e achareis. Lançaram-na, pois, e já não a podiam puxar por causa da grande quantidade de peixes.");
    b->dados[JOAO].capitulos[21].versos[7] = wxT("Então aquele discípulo a quem Jesus amava disse a Pedro: Senhor. Quando, pois, Simão Pedro ouviu que era o Senhor, cingiu-se com a túnica, porque estava despido, e lançou-se ao mar;");
    b->dados[JOAO].capitulos[21].versos[8] = wxT("mas os outros discípulos vieram no barquinho, puxando a rede com os peixes, porque não estavam distantes da terra senão cerca de duzentos côvados.");
    b->dados[JOAO].capitulos[21].versos[9] = wxT("Ora, ao saltarem em terra, viram ali brasas, e um peixe posto em cima delas, e pão.");
    b->dados[JOAO].capitulos[21].versos[10] = wxT("Disse-lhes Jesus: Trazei alguns dos peixes que agora apanhastes.");
    b->dados[JOAO].capitulos[21].versos[11] = wxT("Entrou Simão Pedro no barco e puxou a rede para terra, cheia de cento e cinqüenta e três grandes peixes; e, apesar de serem tantos, não se rompeu a rede.");
    b->dados[JOAO].capitulos[21].versos[12] = wxT("Disse-lhes Jesus: Vinde, comei. Nenhum dos discípulos ousava perguntar-lhe: Quem és tu? sabendo que era o Senhor.");
    b->dados[JOAO].capitulos[21].versos[13] = wxT("Chegou Jesus, tomou o pão e deu-lho, e semelhantemente o peixe.");
    b->dados[JOAO].capitulos[21].versos[14] = wxT("Foi esta a terceira vez que Jesus se manifestou aos seus discípulos, depois de ter ressurgido dentre os mortos.");
    b->dados[JOAO].capitulos[21].versos[15] = wxT("Depois de terem comido, perguntou Jesus a Simão Pedro: Simão Pedro: Simão, filho de João, amas-me mais do que estes? Respondeu-lhe: Sim, Senhor; tu sabes que te amo. Disse-lhe: Apascenta os meus cordeirinhos.");
    b->dados[JOAO].capitulos[21].versos[16] = wxT("Tornou a perguntar-lhe: Simão, filho de João, amas-me? Respondeu-lhe: Sim, Senhor; tu sabes que te amo. Disse-lhe: Pastoreia as minhas ovelhas.");
    b->dados[JOAO].capitulos[21].versos[17] = wxT("Perguntou-lhe terceira vez: Simão, filho de João, amas-me? Entristeceu-se Pedro por lhe ter perguntado pela terceira vez: Amas-me? E respondeu-lhe: Senhor, tu sabes todas as coisas; tu sabes que te amo. Disse-lhe Jesus: Apascenta as minhas ovelhas.");
    b->dados[JOAO].capitulos[21].versos[18] = wxT("Em verdade, em verdade te digo que, quando eras mais moço, te cingias a ti mesmo, e andavas por onde querias; mas, quando fores velho, estenderás as mãos e outro te cingirá, e te levará para onde tu não queres.");
    b->dados[JOAO].capitulos[21].versos[19] = wxT("Ora, isto ele disse, significando com que morte havia Pedro de glorificar a Deus. E, havendo dito isto, ordenou-lhe: Segue-me.");
    b->dados[JOAO].capitulos[21].versos[20] = wxT("E Pedro, virando-se, viu que o seguia aquele discípulo a quem Jesus amava, o mesmo que na ceia se recostara sobre o peito de Jesus e perguntara: Senhor, quem é o que te trai?");
    b->dados[JOAO].capitulos[21].versos[21] = wxT("Ora, vendo Pedro a este, perguntou a Jesus: Senhor, e deste que será?");
    b->dados[JOAO].capitulos[21].versos[22] = wxT("Respondeu-lhe Jesus: Se eu quiser que ele fique até que eu venha, que tens tu com isso? Segue-me tu.");
    b->dados[JOAO].capitulos[21].versos[23] = wxT("Divulgou-se, pois, entre os irmãos este dito, que aquele discípulo não havia de morrer. Jesus, porém, não disse que não morreria, mas: se eu quiser que ele fique até que eu venha, que tens tu com isso?");
    b->dados[JOAO].capitulos[21].versos[24] = wxT("Este é o discípulo que dá testemunho destas coisas e as escreveu; e sabemos que o seu testemunho é verdadeiro.");
    b->dados[JOAO].capitulos[21].versos[25] = wxT("E ainda muitas outras coisas há que Jesus fez; as quais, se fossem escritas uma por uma, creio que nem ainda no mundo inteiro caberiam os livros que se escrevessem.");

}
